# ─────────────────────────────────────────────────────────────────────────
# Preset overrides (loaded from preset_overrides.json if present)
#
# This lets data-driven tuning (apply_preset_tuning.py) update default
# `params`/`dt`/`default_size` without editing source. Format:
#   {"<rule_name>": {"params": {...optional...}, "dt": <optional>,
#                    "default_size": <optional>, "search_size": <optional>}}
# Only the listed keys per rule are merged; everything else is preserved.
# Set CA_DISABLE_PRESET_OVERRIDES=1 to bypass (e.g. for regression baselines).
# ─────────────────────────────────────────────────────────────────────────
def _apply_preset_overrides():
    import json as _json
    import os as _os
    if _os.environ.get('CA_DISABLE_PRESET_OVERRIDES', '0') == '1':
        return 0, []
    here = _os.path.dirname(_os.path.abspath(__file__))
    path = _os.path.join(here, 'preset_overrides.json')
    if not _os.path.isfile(path):
        return 0, []
    try:
        with open(path) as f:
            raw = _json.load(f)
    except Exception as e:
        print(f"[preset_overrides] failed to load {path}: {e}")
        return 0, []
    overrides = raw.get('overrides', raw) if isinstance(raw, dict) else {}
    # Excludelist: rules where median-of-top-discoveries pushes the rule
    # into a chaotic / personality-erasing regime. Keep their pristine
    # source defaults; the patcher will keep regenerating these into the
    # JSON, so we filter at load time. To re-include one, remove it here.
    blocked = raw.get('excludelist', [
        'lenia_3d',         # patch dt 0.05→0.181 violates source's stability comment
        'sine_gordon_3d',   # patch turns elegant solitons into forced chaos
        'element_ca',       # patch jumps to high-energy chemistry regime
    ])
    applied = []
    skipped = []
    for rule, patch in overrides.items():
        if rule in blocked:
            skipped.append((rule, 'excludelist'))
            continue
        if rule not in RULE_PRESETS:
            skipped.append((rule, 'unknown rule'))
            continue
        preset = RULE_PRESETS[rule]
        if 'params' in patch and isinstance(patch['params'], dict):
            cur = dict(preset.get('params', {}))
            for k, v in patch['params'].items():
                if k in cur:
                    cur[k] = v
            preset['params'] = cur
        for key in ('dt', 'default_size', 'search_size'):
            if key in patch:
                preset[key] = patch[key]
        applied.append(rule)
    return len(applied), skipped

_OVR_N, _OVR_SKIP = _apply_preset_overrides()
if _OVR_N or _OVR_SKIP:
    print(f"[preset_overrides] applied {_OVR_N} rule patches"
          + (f"; skipped {len(_OVR_SKIP)}: {_OVR_SKIP}" if _OVR_SKIP else ""))


# ── Initialization patterns (all return 4-channel: size x size x size x 4) ──

# All init functions generate random fields at a fixed canonical resolution
# (CANONICAL_INIT_SIZE³), then upsample to the target size. This ensures the
# same seed produces the same spatial pattern regardless of grid resolution.
CANONICAL_INIT_SIZE = 64


def _fast_upsample_3d(coarse, target_size):
    """Nearest-neighbor upsample a 3-D float array to (target_size,)*3.
    ~50x faster than scipy.ndimage.zoom(order=1) for the power-of-two
    factors used by fBm octaves. For linear quality, the subsequent
    per-octave summation plus final clip produces visually equivalent
    multi-scale noise; reproducibility is preserved within each size
    bucket (same seed -> same output)."""
    cs = coarse.shape[0]
    if cs == target_size:
        return coarse
    if target_size > cs and target_size % cs == 0:
        # Upsample by integer repeat along each axis.
        f = target_size // cs
        return np.repeat(np.repeat(np.repeat(coarse, f, 0), f, 1), f, 2)
    if target_size < cs and cs % target_size == 0:
        # Downsample by block averaging (mean over f×f×f cubes).
        f = cs // target_size
        return coarse.reshape(target_size, f, target_size, f, target_size, f).mean(axis=(1, 3, 5)).astype(coarse.dtype)
    # Fallback for non-integer ratios: single scipy call.
    from scipy.ndimage import zoom
    return zoom(coarse, target_size / cs, order=1).astype(coarse.dtype)


def _canonical_noise(size, rng, low=0.0, high=1.0):
    """Generate a 3D random field at canonical res, upsample to target size.
    Always draws the same number of random values regardless of target size."""
    cs = CANONICAL_INIT_SIZE
    small = rng.uniform(low, high, (cs, cs, cs)).astype(np.float32)
    return _fast_upsample_3d(small, size)


def _canonical_randint(size, rng, choices):
    """Generate a 3D field of integer choices at canonical res, upsample (nearest)."""
    cs = CANONICAL_INIT_SIZE
    small = rng.choice(choices, size=(cs, cs, cs)).astype(np.float32)
    if size == cs:
        return small
    # Nearest-neighbor upsample preserves integer values exactly.
    if size > cs and size % cs == 0:
        f = size // cs
        return np.repeat(np.repeat(np.repeat(small, f, 0), f, 1), f, 2)
    if size < cs and cs % size == 0:
        f = cs // size
        # Take corner of each block (mode-of-block would be correct; this is
        # close enough given the field is i.i.d. and we only need plausible
        # spatial continuity at the output scale).
        return small[::f, ::f, ::f]
    from scipy.ndimage import zoom
    return np.round(zoom(small, size / cs, order=0)).astype(np.float32)


def _canonical_fbm(size, rng, octaves=5, persistence=0.5, lacunarity=2.0):
    """Multi-scale (fractional Brownian motion) noise in [0,1].

    Critical for life-family CAs: uniform single-scale random noise has no
    structure at the kernel wavelength, so every cell sees the same
    neighbourhood mean and dynamics collapse to uniform decay/growth.
    FBM guarantees spatial variation at *every* scale from voxel-sized
    up to grid-sized, so some region is always in the rule's Goldilocks
    density band regardless of kernel radius.

    Returns a (size, size, size) float32 field with mean ~0.5, range [0,1].
    Generated at canonical resolution and upsampled, so seed determines
    pattern identity regardless of grid size.
    """
    cs = CANONICAL_INIT_SIZE
    # Start each octave at a coarser resolution then upsample; this
    # produces proper multi-scale structure rather than just several
    # copies of the same white noise.
    field = np.zeros((cs, cs, cs), dtype=np.float32)
    amp = 1.0
    norm = 0.0
    freq = 1.0
    for _ in range(octaves):
        coarse_size = max(2, int(cs / freq))
        coarse = rng.uniform(0.0, 1.0, (coarse_size, coarse_size, coarse_size)).astype(np.float32)
        if coarse_size != cs:
            layer = _fast_upsample_3d(coarse, cs)
        else:
            layer = coarse
        field += amp * layer
        norm += amp
        amp *= persistence
        freq *= lacunarity
    field /= max(norm, 1e-6)
    if size != cs:
        field = _fast_upsample_3d(field, size)
    return np.clip(field, 0.0, 1.0)


def _fbm_binary_density(size, rng, target_density, octaves=5):
    """FBM noise thresholded to produce a binary field with the specified
    mean density. Used for discrete life-family rules (GoL, 4/4/5) where
    viable dynamics live in a narrow density band and uniform random
    noise at that density has no spatial structure at the kernel scale.

    Threshold is chosen from the actual field quantile so the achieved
    density matches the target even when the FBM distribution is skewed.
    """
    field = _canonical_fbm(size, rng, octaves=octaves)
    # Pick the threshold from the distribution so density is accurate,
    # rather than relying on the theoretical [0,1] uniform quantile.
    threshold = np.quantile(field, 1.0 - target_density)
    return (field > threshold).astype(np.float32)


def _localized_envelope(size, rng, fill_fraction=0.5, edge_softness=0.15):
    """Smooth ball-shaped envelope that fades from 1.0 at the centre to 0
    near the boundaries. Used to localize FBM initial conditions to a
    sub-region of the box, leaving empty space around it so emergent
    creatures have somewhere to move into and stable patterns are
    visible against background.

    fill_fraction = radius of the unit-amplitude core relative to box
                    half-width (0.5 = central half of the box)
    edge_softness = width of the smoothstep falloff in box-half-widths

    Returns a (size, size, size) float32 field in [0,1].
    """
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    half = size / 2.0
    # Centre with a small random offset so the envelope isn't always identical.
    cx = half + rng.uniform(-0.05, 0.05) * size
    cy = half + rng.uniform(-0.05, 0.05) * size
    cz = half + rng.uniform(-0.05, 0.05) * size
    r = np.sqrt((x - cx)**2 + (y - cy)**2 + (z - cz)**2) / half
    # 1.0 inside fill_fraction radius, smooth falloff to 0 over edge_softness.
    inner = fill_fraction
    outer = fill_fraction + edge_softness
    # smoothstep: 1 - smoothstep(inner, outer, r)
    t = np.clip((r - inner) / max(outer - inner, 1e-6), 0.0, 1.0)
    smoothstep = t * t * (3.0 - 2.0 * t)
    return (1.0 - smoothstep).astype(np.float32)


def init_random_very_sparse(size, rng):
    """Random with ~3% density — for crystal rules that grow."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    data[:, :, :, 0] = (_canonical_noise(size, rng) < 0.03).astype(np.float32)
    return data


def init_life_fbm_sparse(size, rng):
    """FBM-thresholded binary field at ~4% density inside a localized
    soft-edged ball, surrounded by empty space. The envelope is critical:
    a uniform-density init at any density just fills the box with
    structure -- there's no empty space for emergent gliders to traverse
    or for stable patterns to be visible against. Localized soup is the
    canonical Life IC: a patch of activity in an empty box."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    field = _canonical_fbm(size, rng, octaves=5)
    envelope = _localized_envelope(size, rng, fill_fraction=0.45, edge_softness=0.20)
    field = field * envelope
    # Density is measured against the envelope-weighted total so the
    # *active region* hits the target density rather than the whole box.
    threshold = np.quantile(field, 1.0 - 0.04 * envelope.mean())
    data[:, :, :, 0] = (field > threshold).astype(np.float32)
    return data


def init_life_fbm_moderate(size, rng):
    """FBM-thresholded binary field at ~18% density inside a localized
    central ball. Active region has the right local density for 3D Life
    survival; surrounding empty space gives gliders/oscillators room to
    propagate and remain visible."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    field = _canonical_fbm(size, rng, octaves=5)
    envelope = _localized_envelope(size, rng, fill_fraction=0.45, edge_softness=0.20)
    field = field * envelope
    threshold = np.quantile(field, 1.0 - 0.18 * envelope.mean())
    data[:, :, :, 0] = (field > threshold).astype(np.float32)
    return data


def init_life_fbm_dense(size, rng):
    """FBM-thresholded binary field at ~30% density in a localized ball.
    Use when the rule needs high local connectivity to nucleate stable
    structures (oscillators, large blobs)."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    field = _canonical_fbm(size, rng, octaves=5)
    envelope = _localized_envelope(size, rng, fill_fraction=0.45, edge_softness=0.20)
    field = field * envelope
    threshold = np.quantile(field, 1.0 - 0.30 * envelope.mean())
    data[:, :, :, 0] = (field > threshold).astype(np.float32)
    return data


def init_smoothlife_fbm(size, rng):
    """FBM-based continuous field for SmoothLife, localized to a central
    ball with empty surround. Active region has FBM mean ~0.22 (matches
    survival window) with multi-scale variation so local maxima are in
    the birth window and local minima are in the death window. Empty
    surround gives nucleated creatures room to move/grow."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    field = _canonical_fbm(size, rng, octaves=5)
    field = 0.22 + 0.85 * (field - field.mean())
    field = np.clip(field, 0.0, 1.0)
    envelope = _localized_envelope(size, rng, fill_fraction=0.4, edge_softness=0.20)
    data[:, :, :, 0] = (field * envelope).astype(np.float32)
    return data


def init_lenia_fbm(size, rng):
    """FBM field tuned for Lenia, localized to a central ball with empty
    surround. Mean density inside the ball sits below mu (growth center)
    with multi-scale structure so local peaks fall in the narrow growth
    band. Surrounding emptiness gives Lenia gliders/orbiums room to
    travel and remain visible against background.

    Tuning: active region mean 0.10, peak ~0.28. Also seeds a few small
    Gaussian "creatures" within the ball so classic Lenia patterns can
    nucleate from the FBM soup."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    field = _canonical_fbm(size, rng, octaves=4)
    field = 0.10 + 0.60 * (field - field.mean())
    field = np.clip(field, 0.0, 1.0)
    envelope = _localized_envelope(size, rng, fill_fraction=0.4, edge_softness=0.20)
    base = (field * envelope).astype(np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    n_blobs = rng.randint(2, 5)
    half = size / 2.0
    for _ in range(n_blobs):
        # Place seeds inside the active region, not in the empty surround.
        cx, cy, cz = (half + rng.uniform(-0.25, 0.25, 3) * size)
        r = rng.uniform(0.06, 0.12) * size
        d2 = ((x - cx)**2 + (y - cy)**2 + (z - cz)**2) / (r * r)
        base += (0.4 * np.exp(-0.5 * d2)).astype(np.float32)
    data[:, :, :, 0] = np.clip(base, 0.0, 1.0)
    return data


def init_lenia_multi_fbm(size, rng):
    """FBM-based init for multi-channel Lenia, localized to a central ball.
    Three channels each get an independent FBM field tuned to sit just
    below mu, plus a small number of Gaussian seeds inside the active
    ball. Channels share the spatial envelope so cross-channel coupling
    has signal everywhere it matters, but the empty surround eliminates
    the "channels die in regions with no signal" pathology."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    half = size / 2.0
    envelope = _localized_envelope(size, rng, fill_fraction=0.4, edge_softness=0.20)
    for ch in range(3):
        field = _canonical_fbm(size, rng, octaves=4)
        field = 0.10 + 0.55 * (field - field.mean())
        field = np.clip(field, 0.0, 1.0)
        base = (field * envelope).astype(np.float32)
        n_blobs = rng.randint(2, 4)
        for _ in range(n_blobs):
            cx, cy, cz = (half + rng.uniform(-0.25, 0.25, 3) * size)
            r = rng.uniform(0.06, 0.12) * size
            d2 = ((x - cx)**2 + (y - cy)**2 + (z - cz)**2) / (r * r)
            base += (0.35 * np.exp(-0.5 * d2)).astype(np.float32)
        data[:, :, :, ch] = np.clip(base, 0.0, 1.0)
    return data


def init_random_sparse(size, rng):
    """Random with ~10% density."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    data[:, :, :, 0] = (_canonical_noise(size, rng) < 0.10).astype(np.float32)
    return data


def init_blank(size, rng):
    """All-zero field. Used by entity-arena scenarios that paint their
    entire visualization from entities each frame."""
    return np.zeros((size, size, size, 4), dtype=np.float32)


def init_food_seed(size, rng):
    """Seed ch3 (alpha) with low-density food noise + a few hot patches.

    Used by the predator-prey preset so logistic growth (food += r * food *
    (1 - food)) has something to amplify from. Without this, food=0
    everywhere and prey starve immediately.
    """
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    # Background: uniform low food density.
    bg = rng.random((size, size, size)).astype(np.float32) * 0.05 + 0.02
    # Hot patches: ~50 sparse seed blobs at ~0.5 food.
    n_blobs = 50
    for _ in range(n_blobs):
        cx = int(rng.random() * size)
        cy = int(rng.random() * size)
        cz = int(rng.random() * size)
        rr = max(2, size // 24)
        x0, x1 = max(0, cx - rr), min(size, cx + rr + 1)
        y0, y1 = max(0, cy - rr), min(size, cy + rr + 1)
        z0, z1 = max(0, cz - rr), min(size, cz + rr + 1)
        bg[x0:x1, y0:y1, z0:z1] = np.maximum(bg[x0:x1, y0:y1, z0:z1], 0.5)
    data[..., 3] = bg
    # ch0 background mirrors food so first frame isn't pure black.
    data[..., 0] = bg * 0.30
    return data

def init_predator_prey_lattice(size, rng):
    """Initial state for the lattice predator-prey CA.

    ch0 encodes the cell kind: 0=empty, 1=food, 2=prey, 3=predator.
    Densities tuned to give the rule a fair starting point — too much
    food and prey explode, too few predators and the system never enters
    the cycling regime.
    """
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    n = size ** 3
    # Generate one uniform random field, partition by quantile thresholds.
    r = rng.random((size, size, size)).astype(np.float32)
    # ~3% food, ~1.5% prey, ~0.1% predator, ~95.4% empty.
    # Sparser than 5/2/0.15% so the grid doesn't look like noise from far,
    # but dense enough that prey reliably stumble onto food in 1-cell hops.
    food_mask = r < 0.030
    prey_mask = (r >= 0.030) & (r < 0.045)
    pred_mask = (r >= 0.045) & (r < 0.046)
    kind = np.zeros((size, size, size), dtype=np.float32)
    # Encode normalized: empty=0, food=0.25, prey=0.50, predator=0.75.
    # Stays away from value=1.0 which trips the voxel renderer's
    # "binary CA" grayscale-AO branch.
    kind[food_mask] = 0.25
    kind[prey_mask] = 0.50
    kind[pred_mask] = 0.75
    data[..., 0] = kind
    # Initial energies: food=1.0 nominal; prey/pred = 0.6..1.0
    energy = np.zeros((size, size, size), dtype=np.float32)
    energy[food_mask] = 1.0
    energy[prey_mask | pred_mask] = 0.6 + rng.random((size, size, size)).astype(np.float32)[prey_mask | pred_mask] * 0.4
    data[..., 1] = energy
    return data

def init_random_dense(size, rng):
    """Random with ~40% density."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    data[:, :, :, 0] = (_canonical_noise(size, rng) < 0.40).astype(np.float32)
    return data

def init_random_smooth(size, rng):
    """Smooth random blobs."""
    # Generate + blur at canonical res, then upsample (inherently smooth)
    from scipy.ndimage import zoom
    cs = CANONICAL_INIT_SIZE
    field = rng.random((cs, cs, cs)).astype(np.float32) * 0.5
    for _ in range(3):
        padded = np.pad(field, 1, mode='wrap')
        field = (padded[:-2, 1:-1, 1:-1] + padded[2:, 1:-1, 1:-1] +
                 padded[1:-1, :-2, 1:-1] + padded[1:-1, 2:, 1:-1] +
                 padded[1:-1, 1:-1, :-2] + padded[1:-1, 1:-1, 2:] +
                 padded[1:-1, 1:-1, 1:-1]) / 7.0
    if size != cs:
        field = zoom(field, size / cs, order=1).astype(np.float32)
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    data[:, :, :, 0] = field
    return data

def init_center_blob(size, rng):
    """Gaussian blob at center."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    c = size / 2.0
    r = size / 8.0
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    dist = np.sqrt((x - c)**2 + (y - c)**2 + (z - c)**2)
    data[:, :, :, 0] = np.exp(-0.5 * (dist / (r * 0.3))**2).astype(np.float32)
    return data

def init_crystal_dla_seed(size, rng):
    """DLA / dielectric-breakdown seed: single solid cell at centre,
    surrounding potential field initialised to 1.0 (the "infinity"
    reservoir). Growth happens at the front via the harmonic-measure
    driven shader; the result is a fractal cluster.

    R = phase (0=empty, 1=solid). Seed is a single cell.
    G = potential phi_e (Laplace solution, =0 on cluster, =1 at boundary).
        Initialised uniformly to 1.0; the shader will relax it to satisfy
        Laplace(phi_e) = 0 with phi_e=0 on the cluster as the cluster grows.
    B = age (frame index packed normalised; for visualisation gradient).
    A = visualisation channel (set at solidification time to the local
        |grad phi_e|^eta -- shows tip activity at moment of growth).
    """
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    # Potential field: start at 1.0 everywhere (reservoir at infinity).
    data[:, :, :, 1] = 1.0
    # Single seed at exact centre.
    cx, cy, cz = size // 2, size // 2, size // 2
    data[cx, cy, cz, 0] = 1.0     # solid
    data[cx, cy, cz, 1] = 0.0     # potential clamped to 0 on cluster
    return data

def init_crystal_dla_multi_seed(size, rng):
    """DLA seed variant: multiple seeds scattered through the box.

    Useful for showing how separate clusters compete for the same field:
    each cluster shadows its neighbours' potential, and the resulting
    branches are drawn toward gaps in the seed pattern. Visually richer
    than the single-seed canonical case.
    """
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    data[:, :, :, 1] = 1.0
    n_seeds = rng.randint(4, 9)
    for _ in range(n_seeds):
        # Avoid the boundary band where the Dirichlet BC shorts out the
        # potential (a seed there would just race outward into the wall).
        cx = rng.randint(int(size * 0.2), int(size * 0.8))
        cy = rng.randint(int(size * 0.2), int(size * 0.8))
        cz = rng.randint(int(size * 0.2), int(size * 0.8))
        data[cx, cy, cz, 0] = 1.0
        data[cx, cy, cz, 1] = 0.0
    return data

def init_crystal_seed(size, rng):
    """Phase-field crystal seed: single centred solid seed in undercooled melt.

    Used by the single-crystal presets (compact/octahedral/cubic) where the
    point is to watch one well-formed crystal grow symmetrically — so we
    place one small seed near the middle and fill the box with full
    supersaturation so the growth front has plenty of melt to consume.
    """
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    # R = phase field: start liquid (φ≈0)
    data[:, :, :, 0] = 0.0
    # G = supersaturation: limited reservoir (u_init=0.25) so each
    # solidification (which consumes 0.5 of u via partition rejection)
    # caps the crystal at ~50% of the box -- enough to clearly resolve
    # the morphology, finite enough that growth halts before hitting
    # the wall and erasing the transient shape. Plus small noise so the
    # symmetry-breaking that picks <100> vs <111> bulges has something
    # to bite on (perfectly symmetric data → no preferred direction
    # at the seed).
    data[:, :, :, 1] = 0.25 + _canonical_noise(size, rng, -0.005, 0.005)
    # One seed slightly off-centre so growth is visually centred.
    fx = 0.5 + rng.uniform(-0.04, 0.04)
    fy = 0.5 + rng.uniform(-0.04, 0.04)
    fz = 0.5 + rng.uniform(-0.04, 0.04)
    cx, cy, cz = fx * size, fy * size, fz * size
    r = max(2.0, size * 0.025)
    dist = np.sqrt((x - cx)**2 + (y - cy)**2 + (z - cz)**2)
    mask = dist <= r
    data[:, :, :, 0][mask] = 1.0  # solid
    data[:, :, :, 1][mask] = 0.0  # supersaturation consumed
    return data

def init_crystal_disc_seed(size, rng):
    """Phase-field crystal seed shaped as a thin disc in the xz plane.

    Used by the snowflake preset: real ice nucleates into a thin hexagonal
    plate because the basal-face surface energy is low and the prism faces
    grow laterally much faster than the c-axis. A spherical seed has all
    directions equally represented in its initial gradient, which fights
    against the c-axis suppression in the snowflake β kernel and gives a
    bulky stub before the plate morphology can establish itself. A disc
    seed (thin in y, broad in xz) hands the kernel an interface that's
    already biased toward the right shape, so the hex outline emerges
    from the very first step.
    """
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    data[:, :, :, 0] = 0.0
    data[:, :, :, 1] = 0.25 + _canonical_noise(size, rng, -0.005, 0.005)
    fx = 0.5 + rng.uniform(-0.04, 0.04)
    fy = 0.5 + rng.uniform(-0.04, 0.04)
    fz = 0.5 + rng.uniform(-0.04, 0.04)
    cx, cy, cz = fx * size, fy * size, fz * size
    # Disc: small in y (c-axis), broad in xz (basal plane). Larger r_xz
    # than a sphere seed so the analytical hex kernel resolves cleanly
    # from the first step — if the seed is too small the cube-grid
    # Laplacian's 4-fold bias dominates before β(n̂) can take over and
    # the plate rounds into a sphere, then octahedron. y_half stays
    # minimal because the snowflake β kernel suppresses c-axis growth
    # to keep the plate thin.
    r_xz = max(5.0, size * 0.08)
    y_half = max(1.5, size * 0.012)
    in_disc = ((x - cx)**2 + (z - cz)**2 <= r_xz * r_xz) & (np.abs(y - cy) <= y_half)
    data[:, :, :, 0][in_disc] = 1.0
    data[:, :, :, 1][in_disc] = 0.0
    return data

def init_schnakenberg(size, rng):
    """Schnakenberg: start near the homogeneous fixed point with small
    spatial noise. The Turing instability amplifies wavelengths in the
    unstable band, growing organic spots from initial roughness."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    a, b = 0.1, 0.9
    U_star = a + b
    V_star = b / max(U_star * U_star, 1e-6)
    data[:, :, :, 0] = U_star + rng.uniform(-0.02, 0.02, (size, size, size)).astype(np.float32)
    data[:, :, :, 1] = V_star + rng.uniform(-0.02, 0.02, (size, size, size)).astype(np.float32)
    return data

def init_fitzhugh_nagumo(size, rng):
    """FN: quiescent V=−1, W=−2/3 (resting state), with one or two
    suprathreshold blobs to trigger propagating pulses."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    data[:, :, :, 0] = -1.0
    data[:, :, :, 1] = -2.0 / 3.0
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    n_blobs = rng.randint(1, 3)
    for _ in range(n_blobs):
        cx = rng.uniform(0.2, 0.8) * size
        cy = rng.uniform(0.2, 0.8) * size
        cz = rng.uniform(0.2, 0.8) * size
        r  = max(2.0, size / 14.0)
        d2 = (x - cx) ** 2 + (y - cy) ** 2 + (z - cz) ** 2
        blob = np.exp(-0.5 * d2 / (r * r)).astype(np.float32)
        data[:, :, :, 0] += 2.5 * blob   # push V well above threshold
    return data

def init_brusselator(size, rng):
    """Brusselator: start at the homogeneous fixed point U=A, V=B/A
    plus small noise to seed the Turing/Hopf instability."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    A, B = 1.0, 3.0
    U_star = A
    V_star = B / max(A, 1e-6)
    data[:, :, :, 0] = U_star + rng.uniform(-0.05, 0.05, (size, size, size)).astype(np.float32)
    data[:, :, :, 1] = V_star + rng.uniform(-0.05, 0.05, (size, size, size)).astype(np.float32)
    return data

def init_cyclic_ca(size, rng):
    """Cyclic CA: each cell starts in a uniformly random state 0..N-1.
    N defaults to 14 (matches param0 default rounded). Stored in R as
    float; G channel mirrors phase = state/N for visualisation."""
    N = 14
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    states = rng.randint(0, N, (size, size, size)).astype(np.float32)
    data[:, :, :, 0] = states
    data[:, :, :, 1] = states / float(N)
    return data

def init_wave_pulse(size, rng):
    """Wave equation: 1-3 Gaussian pulses at random positions, varying widths."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    n_pulses = rng.randint(1, 4)  # 1-3 pulses
    for _ in range(n_pulses):
        cx = rng.uniform(size * 0.2, size * 0.8)
        cy = rng.uniform(size * 0.2, size * 0.8)
        cz = rng.uniform(size * 0.2, size * 0.8)
        r = rng.uniform(size * 0.03, size * 0.12)
        amp = rng.uniform(0.5, 1.5)
        dist = np.sqrt((x - cx)**2 + (y - cy)**2 + (z - cz)**2)
        data[:, :, :, 0] += (amp * np.exp(-0.5 * (dist / r)**2)).astype(np.float32)
    # Optionally give some pulses initial velocity (not purely displacement)
    if rng.random() < 0.5:
        vr = rng.uniform(size * 0.05, size * 0.15)
        vcx = rng.uniform(size * 0.2, size * 0.8)
        vcy = rng.uniform(size * 0.2, size * 0.8)
        vcz = rng.uniform(size * 0.2, size * 0.8)
        vdist = np.sqrt((x - vcx)**2 + (y - vcy)**2 + (z - vcz)**2)
        data[:, :, :, 1] = (rng.uniform(-1.0, 1.0) * np.exp(-0.5 * (vdist / vr)**2)).astype(np.float32)
    return data

def init_gray_scott(size, rng):
    """Gray-Scott: U=1 everywhere, V seeded in irregular noise-thresholded clusters.
    Irregular splotches instead of spherical patches — the Turing instability
    develops varied pattern orientations immediately rather than expanding as
    a boring ring that slowly breaks symmetry."""
    from scipy.ndimage import gaussian_filter
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    data[:, :, :, 0] = 1.0  # U = 1 everywhere

    # Generate smooth noise field — heavy blur creates large connected
    # clusters when thresholded, producing irregular organic splotches
    cs = CANONICAL_INIT_SIZE
    raw = rng.random((cs, cs, cs)).astype(np.float32)
    blurred = gaussian_filter(raw, sigma=3.0)
    from scipy.ndimage import zoom
    if size != cs:
        blurred = zoom(blurred, size / cs, order=1).astype(np.float32)

    # Threshold to create irregular splotches (~15% volume coverage)
    threshold = np.percentile(blurred, 85)
    mask = blurred > threshold

    # Concentration variation within clusters (breaks any residual symmetry)
    variation = _canonical_noise(size, rng, 0.15, 0.30)
    data[:, :, :, 0][mask] = 0.5
    data[:, :, :, 1][mask] = variation[mask]

    # Low-level noise everywhere for additional symmetry breaking
    noise = _canonical_noise(size, rng, 0.0, 0.01)
    data[:, :, :, 1] += noise

    return data


def init_predator_prey(size, rng):
    """Rosenzweig-MacArthur predator-prey: patchy prey and predator populations.
    Prey patches at carrying capacity with predator clusters trailing behind.
    Spatial heterogeneity triggers traveling pursuit waves and boom-bust cycles."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    mid = size / 2.0

    # Start with prey near carrying capacity everywhere + noise
    prey = 0.8 + _canonical_noise(size, rng, -0.2, 0.2)

    # Add 2-4 predator clusters (scattered hunting packs)
    n_packs = rng.randint(2, 5)
    predator = np.zeros((size, size, size), dtype=np.float32)
    for _ in range(n_packs):
        cx = rng.uniform(size * 0.15, size * 0.85)
        cy = rng.uniform(size * 0.15, size * 0.85)
        cz = rng.uniform(size * 0.15, size * 0.85)
        r = rng.uniform(size * 0.08, size * 0.2)
        amp = rng.uniform(0.3, 0.8)
        dist = np.sqrt((x - cx)**2 + (y - cy)**2 + (z - cz)**2)
        predator += (amp * np.exp(-0.5 * (dist / r)**2)).astype(np.float32)

    # Add a few prey-depleted zones (recently predated areas)
    n_gaps = rng.randint(1, 3)
    for _ in range(n_gaps):
        cx = rng.uniform(size * 0.2, size * 0.8)
        cy = rng.uniform(size * 0.2, size * 0.8)
        cz = rng.uniform(size * 0.2, size * 0.8)
        r = rng.uniform(size * 0.06, size * 0.15)
        dist = np.sqrt((x - cx)**2 + (y - cy)**2 + (z - cz)**2)
        prey -= (0.6 * np.exp(-0.5 * (dist / r)**2)).astype(np.float32)

    data[:, :, :, 0] = np.clip(prey, 0.05, 1.0).astype(np.float32)
    data[:, :, :, 1] = np.clip(predator, 0.0, 1.0).astype(np.float32)

    # Small noise for symmetry breaking
    data[:, :, :, 0] += _canonical_noise(size, rng, 0.0, 0.02)
    data[:, :, :, 1] += _canonical_noise(size, rng, 0.0, 0.01)
    data[:, :, :, 0] = np.clip(data[:, :, :, 0], 0, 1)
    data[:, :, :, 1] = np.clip(data[:, :, :, 1], 0, 1)
    return data


def init_kuramoto(size, rng):
    """Kuramoto: random phases and spatially-varying natural frequencies."""
    from scipy.ndimage import zoom
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    # Random initial phase [0, 1) (represents 0 to 2*pi)
    data[:, :, :, 0] = _canonical_noise(size, rng)
    # Natural frequency: smooth spatial variation (creates interesting domain walls)
    cs = CANONICAL_INIT_SIZE
    freq = rng.random((cs, cs, cs)).astype(np.float32)
    for _ in range(3):
        padded = np.pad(freq, 1, mode='wrap')
        freq = (padded[:-2, 1:-1, 1:-1] + padded[2:, 1:-1, 1:-1] +
                 padded[1:-1, :-2, 1:-1] + padded[1:-1, 2:, 1:-1] +
                 padded[1:-1, 1:-1, :-2] + padded[1:-1, 1:-1, 2:] +
                 padded[1:-1, 1:-1, 1:-1]) / 7.0
    if size != cs:
        freq = zoom(freq, size / cs, order=1).astype(np.float32)
    data[:, :, :, 1] = freq
    return data

def init_bz_reaction(size, rng):
    """BZ/CGLE init: random complex field near the limit cycle |A|=1.
    Start with amplitude ~1 and random phase, with small perturbations.
    The Benjamin-Feir instability breaks this into spiral defect chaos."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)

    # Random phase everywhere [0, 2pi)
    phase = _canonical_noise(size, rng, 0.0, 2 * np.pi)

    # Amplitude near the limit cycle |A| = sqrt(mu) ≈ 1
    # with 10% perturbation to trigger instability
    amp = 1.0 + _canonical_noise(size, rng, -0.1, 0.1)

    data[:, :, :, 0] = (amp * np.cos(phase)).astype(np.float32)  # Re(A)
    data[:, :, :, 1] = (amp * np.sin(phase)).astype(np.float32)  # Im(A)
    data[:, :, :, 2] = (phase / (2 * np.pi)).astype(np.float32)  # Phase for vis
    return data


def init_barkley_excitable(size, rng):
    """Barkley excitable medium: resting state with a few excitation seeds.
    Seeds trigger propagating wavefronts; collisions and refractory zones
    create complex scroll wave dynamics."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    # Resting state: u=0, v=0 (excitable, ready to fire)
    # Place a few excited regions as seeds for wave nucleation
    n_seeds = rng.randint(3, 8)
    for _ in range(n_seeds):
        cx = rng.uniform(size * 0.1, size * 0.9)
        cy = rng.uniform(size * 0.1, size * 0.9)
        cz = rng.uniform(size * 0.1, size * 0.9)
        r = rng.uniform(size * 0.04, size * 0.1)
        dist = np.sqrt((x - cx)**2 + (y - cy)**2 + (z - cz)**2)
        excited = (dist < r).astype(np.float32)
        data[:, :, :, 0] = np.maximum(data[:, :, :, 0], excited)
    # Add a half-plane refractory region to create scroll wave seeds
    # (excitation + perpendicular refractory → scroll wave)
    plane_pos = rng.uniform(0.3, 0.7) * size
    plane_axis = rng.randint(0, 3)
    if plane_axis == 0:
        mask = x > plane_pos
    elif plane_axis == 1:
        mask = y > plane_pos
    else:
        mask = z > plane_pos
    data[:, :, :, 1] = np.where(mask & (data[:, :, :, 0] > 0.5), 0.5, data[:, :, :, 1])
    return data


def init_morphogen(size, rng):
    """Morphogenesis: uniform tissue with random activator perturbations.
    Start near the homogeneous steady state so Turing instability can grow."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    # Approximate GM steady state: a0 ≈ sigma_a/mu_a + correction ≈ 0.1
    # h0 ≈ a0^2/mu_h ≈ 0.01. But we keep it modest to let patterns emerge.
    a0, h0 = 0.2, 0.04  # near but not at equilibrium
    data[:, :, :, 0] = a0
    data[:, :, :, 1] = h0
    data[:, :, :, 2] = 0.5  # tissue density (moderate)
    # Random perturbations to activator to trigger Turing instability
    data[:, :, :, 0] += _canonical_noise(size, rng, -0.05, 0.05)
    data[:, :, :, 0] = np.clip(data[:, :, :, 0], 0.01, None)
    return data


def init_flocking(size, rng):
    """Flocking: elongated density streaks with locally coherent velocities.
    Real flocks form streams and filaments, not spherical blobs. Each streak
    has a coherent bulk velocity so the alignment interaction is visible
    immediately — streaks merge, deflect, and form vortex mills."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    n_streaks = rng.randint(8, 14)
    for _ in range(n_streaks):
        # Random center
        cx = rng.uniform(0.05, 0.95) * size
        cy = rng.uniform(0.05, 0.95) * size
        cz = rng.uniform(0.05, 0.95) * size
        # Random elongation direction
        theta = rng.uniform(0, 2 * np.pi)
        phi = rng.uniform(-np.pi / 2, np.pi / 2)
        dx_dir = np.cos(phi) * np.cos(theta)
        dy_dir = np.cos(phi) * np.sin(theta)
        dz_dir = np.sin(phi)
        # Displacement from center
        rx = (x - cx).astype(np.float64)
        ry = (y - cy).astype(np.float64)
        rz = (z - cz).astype(np.float64)
        # Project along and perpendicular to streak direction
        along = rx * dx_dir + ry * dy_dir + rz * dz_dir
        perp_sq = np.maximum(rx**2 + ry**2 + rz**2 - along**2, 0.0)
        # Elongated Gaussian: long along direction, narrow perpendicular
        long_r = max(3, size // 6)
        short_r = max(2, size // 16)
        density = np.exp(-0.5 * (along / long_r)**2
                         - 0.5 * perp_sq / short_r**2).astype(np.float32)
        density *= rng.uniform(0.3, 0.6)
        data[:, :, :, 0] += density
        # Coherent velocity along streak direction (scaled by local density)
        speed = rng.uniform(0.1, 0.3)
        data[:, :, :, 1] += density * dx_dir * speed
        data[:, :, :, 2] += density * dy_dir * speed
        data[:, :, :, 3] += density * dz_dir * speed
    data[:, :, :, 0] = np.clip(data[:, :, :, 0], 0, 1)
    return data


def init_element_mix(size, rng):
    """Random mix of common elements: C, N, O, Na, Fe, Cu, Au + vacuum."""
    # R=element_id, G=temperature, B=phase, A=velocity
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    common = [0, 0, 0, 0, 6, 7, 8, 11, 26, 29, 79]  # lots of vacuum + elements
    # Melting points for phase determination at 25°C
    mp_lookup = {6: 3550, 7: -210, 8: -219, 11: 98, 26: 1538, 29: 1085, 79: 1064}

    ids = _canonical_randint(size, rng, common)
    data[:, :, :, 0] = ids
    data[:, :, :, 1] = 25.0  # room temperature

    # Compute phase for each cell
    for z_id, mp in mp_lookup.items():
        mask = ids == z_id
        if mp > 25:
            data[:, :, :, 2][mask] = 0.0  # solid
        elif z_id in (7, 8):  # N, O: gas at room temp
            data[:, :, :, 2][mask] = 2.0  # gas
        else:
            data[:, :, :, 2][mask] = 1.0  # liquid

    return data


def init_sodium_water(size, rng):
    """Pool of water (H+O) at bottom, sodium chunk dropped from top."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    half = size // 2

    # Bottom half in Y (vertical axis): alternating H and O (simplified water)
    for y in range(half):
        for z in range(size):
            for x in range(size):
                data[z, y, x, 0] = 8.0 if ((x + y + z) % 2 == 0) else 1.0  # O and H
                data[z, y, x, 1] = 25.0  # room temp
                data[z, y, x, 2] = 1.0   # liquid

    # Top-center: sodium block (high Y = top, centered X/Z)
    c = size // 2
    r = max(2, size // 10)
    for y in range(half + 2, half + 2 + r):
        for z in range(c - r, c + r):
            for x in range(c - r, c + r):
                if 0 <= y < size and 0 <= z < size and 0 <= x < size:
                    data[z, y, x, 0] = 11.0  # Na
                    data[z, y, x, 1] = 25.0
                    data[z, y, x, 2] = 0.0  # solid
                    data[z, y, x, 3] = -1.0  # falling

    return data


def init_metal_layers(size, rng):
    """Layers of metals with different melting points: Sn(232°C), Pb(327°C), Cu(1085°C), Fe(1538°C)."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)

    # Wall floor at y=0 to catch melting metals
    data[:, 0, :, 0] = float(WALL_ID)
    data[:, 0, :, 1] = 25.0
    data[:, 0, :, 2] = 0.0

    metals = [50, 82, 29, 26]  # Sn, Pb, Cu, Fe from bottom to top
    n_layers = len(metals)
    # Layers start at y=1 (above wall floor), with gaps between
    layer_h = max(2, (size - 1) // (n_layers + 2))

    for i, metal_z in enumerate(metals):
        y_start = 1 + i * (layer_h + 1)  # +1 for gap row between layers
        y_end = min(y_start + layer_h, size)
        data[:, y_start:y_end, :, 0] = float(metal_z)
        data[:, y_start:y_end, :, 1] = 500.0  # pre-heated
        data[:, y_start:y_end, :, 2] = 0.0     # solid

    # Sn melts at 232°C so at 500°C it's liquid
    y0 = 1
    data[:, y0:y0+layer_h, :, 2] = 1.0  # Sn = liquid at 500°C
    # Pb melts at 327°C so at 500°C it's also liquid
    y1 = 1 + layer_h + 1
    data[:, y1:y1+layer_h, :, 2] = 1.0  # Pb = liquid at 500°C

    return data


def init_lenia_blobs(size, rng):
    """Lenia: ellipsoidal blobs with random aspect ratios and surface noise.
    Lenia creatures are defined by shape — spherical seeds converge to the
    same morphology from every direction. Elongated, noisy starts produce
    more varied creature types."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    n_blobs = rng.randint(2, 8)
    # Surface noise to roughen blob boundaries
    surface_noise = _canonical_noise(size, rng, 0.7, 1.3)
    for _ in range(n_blobs):
        fx = rng.uniform(1.0/6, 5.0/6)
        fy = rng.uniform(1.0/6, 5.0/6)
        fz = rng.uniform(1.0/6, 5.0/6)
        cx, cy, cz = fx * size, fy * size, fz * size
        fr = rng.uniform(1.0/16, 1.0/6)
        base_r = fr * size
        # Random aspect ratios: each axis independently scaled 0.5x-2.0x
        ax = base_r * rng.uniform(0.5, 2.0)
        ay = base_r * rng.uniform(0.5, 2.0)
        az = base_r * rng.uniform(0.5, 2.0)
        # Ellipsoidal distance
        edist = np.sqrt(((x - cx) / max(ax, 1))**2 +
                        ((y - cy) / max(ay, 1))**2 +
                        ((z - cz) / max(az, 1))**2)
        amp = rng.uniform(0.3, 0.9)
        blob = (amp * np.exp(-0.5 * (edist / 0.4)**2) * surface_noise).astype(np.float32)
        data[:, :, :, 0] += blob
    data[:, :, :, 0] = np.clip(data[:, :, :, 0], 0.0, 1.0)
    return data


def init_lenia_multi(size, rng):
    """Multi-channel Lenia: 3 channels with overlapping but distinct blob patterns.
    Each channel starts with different blob placements so cross-channel
    interactions create asymmetric dynamics from the start."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    surface_noise = _canonical_noise(size, rng, 0.7, 1.3)
    for ch in range(3):
        n_blobs = rng.randint(2, 6)
        for _ in range(n_blobs):
            cx = rng.uniform(size * 0.15, size * 0.85)
            cy = rng.uniform(size * 0.15, size * 0.85)
            cz = rng.uniform(size * 0.15, size * 0.85)
            base_r = rng.uniform(size * 0.06, size * 0.15)
            ax = base_r * rng.uniform(0.6, 1.8)
            ay = base_r * rng.uniform(0.6, 1.8)
            az = base_r * rng.uniform(0.6, 1.8)
            edist = np.sqrt(((x - cx)/max(ax,1))**2 + ((y - cy)/max(ay,1))**2 + ((z - cz)/max(az,1))**2)
            amp = rng.uniform(0.3, 0.8)
            blob = (amp * np.exp(-0.5 * (edist / 0.4)**2) * surface_noise).astype(np.float32)
            data[:, :, :, ch] += blob
        data[:, :, :, ch] = np.clip(data[:, :, :, ch], 0.0, 1.0)
    return data


def init_phase_separation(size, rng):
    """Cahn-Hilliard: near-zero order parameter with small perturbations (spinodal regime)."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    # Small random perturbations around c=0 (unstable mixed state)
    data[:, :, :, 0] = _canonical_noise(size, rng, -0.05, 0.05)
    # G channel (chemical potential) starts at zero
    return data

def init_nucleation(size, rng):
    """Off-critical Cahn-Hilliard: bias mean concentration toward majority
    phase so the minority phase nucleates as discrete droplets.

    Cahn-Hilliard *conserves* total mass (∂ₜc = ∇²μ → ∫c dV is conserved),
    so a 50/50 zero-mean init can never produce droplets regardless of the
    asymmetry parameter. With asymmetry≈0.3 the deep well sits at c≈-1
    and the shallow well at c≈+0.88. Starting at mean c≈+0.4 places the
    system in the metastable region: by mass conservation roughly a third
    of the volume must convert to the deep "−" phase, doing so as discrete
    droplets in a "+" sea.
    """
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    base = 0.4  # metastable, near shallow "+" well
    data[:, :, :, 0] = (base + _canonical_noise(size, rng, -0.1, 0.1)).astype(np.float32)
    return data

def init_erosion_terrain(size, rng):
    """Erosion: solid terrain block with water source at top."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    # Solid terrain fills bottom 60% with some noise for variation
    terrain_height = int(size * 0.6)
    noise = _canonical_noise(size, rng, -0.1, 0.1)
    for y in range(size):
        base = 1.0 if y < terrain_height else 0.0
        # Rough surface near the terrain boundary
        if abs(y - terrain_height) < size // 8:
            data[:, y, :, 0] = np.clip(base + noise[:, y, :], 0.0, 1.0)
        else:
            data[:, y, :, 0] = base
    # Water source: thin layer at top
    data[:, -2:, :, 1] = 0.8
    return data

def init_mycelium(size, rng):
    """Mycelium: nutrient field with tiny linear seed filaments."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    # Channel 1 = nutrient: smooth random field 0.5-1.0
    data[:, :, :, 1] = _canonical_noise(size, rng, 0.5, 1.0)
    # Channel 0 = biomass: short filament seeds (3 voxels each)
    n_seeds = rng.randint(5, 15)
    for _ in range(n_seeds):
        sx = rng.randint(size // 4, 3 * size // 4)
        sy = rng.randint(size // 4, 3 * size // 4)
        sz = rng.randint(size // 4, 3 * size // 4)
        axis = rng.randint(0, 3)  # random direction
        for step in range(3):
            px, py, pz = sx, sy, sz
            if axis == 0: px += step
            elif axis == 1: py += step
            else: pz += step
            if 0 <= px < size and 0 <= py < size and 0 <= pz < size:
                if step < 2:
                    data[pz, py, px, 0] = 1.0   # established core
                else:
                    data[pz, py, px, 0] = 0.2   # growing tip
                    data[pz, py, px, 3] = 1.0   # tip marker
    return data

def init_em_wave(size, rng):
    """EM wave: Gaussian Ez dipole at the box centre.

    Layout for the new Yee-leapfrog rule:
        Pair 1 = (Ex, Ey, Ez, medium)   — only Ez is seeded
        Pair 2 = (Bx, By, Bz, _)        — starts at zero; B grows
                                          from -∂E/∂t in the first step
    """
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    c = size / 2.0
    r = max(2, size // 10)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    dx = (x - c).astype(np.float64)
    dy = (y - c).astype(np.float64)
    dz = (z - c).astype(np.float64)
    dist = np.sqrt(dx**2 + dy**2 + dz**2)
    envelope = np.exp(-0.5 * (dist / r) ** 2)
    # Dipole Ez ∝ y / r — antisymmetric across y-midplane → proper
    # radiation pattern (lobes above & below the source plane).
    Ez = (envelope * dy / max(r, 1)).astype(np.float32)
    data[:, :, :, 2] = Ez   # Ez slot in (Ex, Ey, Ez, medium)
    return data

def init_em_dipole_pair(size, rng):
    """Two coherent Ez dipoles separated along X — produces classic
    near-field interference (constructive maxima between sources,
    destructive nulls along the perpendicular bisector at certain
    radii) that a single dipole cannot."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    c = size / 2.0
    sep = max(4, size // 4)
    r = max(2, size // 12)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    dy = (y - c).astype(np.float64)
    Ez = np.zeros_like(dy)
    for sign in (-1.0, +1.0):
        cx = c + sign * 0.5 * sep
        dx = (x - cx).astype(np.float64)
        dz = (z - c).astype(np.float64)
        dist = np.sqrt(dx**2 + dy**2 + dz**2)
        env = np.exp(-0.5 * (dist / r) ** 2)
        Ez += env * dy / max(r, 1)
    data[:, :, :, 2] = Ez.astype(np.float32)
    return data

def init_em_plane_wave(size, rng):
    """Travelling Ez plane wave injected from the −X face: an Ez sheet
    of a few cycles sits at small x, with a matched Bz profile so the
    pulse propagates as a unidirectional Poynting flux instead of a
    standing dipole pattern."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    xf = x.astype(np.float64)
    # Wavelength ≈ size/4, envelope a few wavelengths wide near x=0.
    k = 2.0 * np.pi / max(4.0, size / 4.0)
    envelope = np.exp(-0.5 * ((xf - size * 0.1) / max(2.0, size / 16.0)) ** 2)
    wave = envelope * np.sin(k * xf)
    data[:, :, :, 2] = wave.astype(np.float32)            # Ez
    return data

def init_em_cavity_mode(size, rng):
    """TE_111-like resonant cavity mode in a perfect-conductor box:
    Ez filled with sin(πx/L)·sin(πy/L)·sin(πz/L). Excites the lowest
    standing-wave mode of the simulation domain — gives a long-lived
    oscillation whose nodes/antinodes scan beautifully through the
    volume."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    L = float(size)
    Ez = (np.sin(np.pi * x / L) *
          np.sin(np.pi * y / L) *
          np.sin(np.pi * z / L)).astype(np.float32)
    data[:, :, :, 2] = Ez
    return data

def init_em_photonic_crystal(size, rng):
    """3D photonic crystal: cubic lattice of high-permittivity spheres
    embedded in vacuum. The dipole source at box centre radiates into a
    structured medium with a partial photonic band gap — at certain
    frequencies the wave is forbidden from propagating along certain
    directions, producing diffraction patterns and slow-light effects.

    Pair 1: Ez seeded with a small Gaussian pulse + alpha = ε_r map
    Pair 2: B = 0, sigma = 0 (lossless dielectric)

    Lattice constant ≈ size/4 (so 4×4×4 spheres tile the box). Sphere
    radius is ~0.3 × lattice constant — moderate filling fraction
    where the band gap is widest for ε_r ≈ 12 (silicon-like).
    """
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    L = max(8, size // 4)              # lattice constant in cells
    r_sphere = 0.3 * L

    # Distance from each cell to the *nearest* lattice site (modular).
    fx = np.minimum((x % L), L - (x % L)).astype(np.float64)
    fy = np.minimum((y % L), L - (y % L)).astype(np.float64)
    fz = np.minimum((z % L), L - (z % L)).astype(np.float64)
    d2 = fx * fx + fy * fy + fz * fz
    inside = d2 < (r_sphere * r_sphere)

    # ε_r map: 12 inside spheres (Si-like), 1 (vacuum) outside.
    eps_r = np.where(inside, 12.0, 1.0).astype(np.float32)

    # Small Ez seed at the centre to feed the dipole the first cycle.
    cx = size / 2.0
    dx = (x - cx).astype(np.float64)
    dy = (y - cx).astype(np.float64)
    dz = (z - cx).astype(np.float64)
    seed_r = max(2.0, size / 12.0)
    Ez = (0.3 * np.exp(-0.5 * (dx * dx + dy * dy + dz * dz) / (seed_r * seed_r))
          * dy / seed_r).astype(np.float32)

    data[:, :, :, 2] = Ez
    data[:, :, :, 3] = eps_r
    return data

def init_em_photonic_cavity(size, rng):
    """Photonic crystal with a defect: same lattice as em_photonic_crystal
    but one sphere off-centre is removed, creating a localized cavity
    mode that traps light at specific frequencies inside the band gap.
    A small seed pulse is placed inside the cavity so radiation builds
    up there even with the dipole source at box centre."""
    data = init_em_photonic_crystal(size, rng)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    L = max(8, size // 4)
    # Pick a lattice site offset from the box centre by ~1.5 lattice
    # constants so the cavity and the dipole source don't overlap.
    cav_x = size / 2.0 + 1.5 * L
    cav_y = size / 2.0
    cav_z = size / 2.0
    r_remove = 0.45 * L                        # slightly bigger than a sphere
    d2 = (x - cav_x) ** 2 + (y - cav_y) ** 2 + (z - cav_z) ** 2
    inside = d2 < (r_remove * r_remove)
    eps = data[:, :, :, 3]
    eps[inside] = 1.0
    data[:, :, :, 3] = eps
    # Boost a small Ez seed inside the cavity so the trapped mode has
    # something to ring on even before the dipole source feeds energy in.
    seed_r = 0.35 * L
    seed_d2 = (x - cav_x) ** 2 + (y - cav_y) ** 2 + (z - cav_z) ** 2
    seed = np.exp(-0.5 * seed_d2 / (seed_r * seed_r))
    data[:, :, :, 2] += (0.5 * seed * (y - cav_y) / seed_r).astype(np.float32)
    return data

def init_em_beam_splitter(size, rng):
    """Two perpendicular waveguides crossing at the box centre. A pulse
    injected into one arm couples partially into the orthogonal arm at
    the junction — classic 4-port photonic device."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    cx, cy, cz = size / 2.0, size / 2.0, size / 2.0
    half_w = max(2, size // 10)

    in_z_guide = (np.abs(x - cx) <= half_w) & (np.abs(y - cy) <= half_w)
    in_x_guide = (np.abs(z - cz) <= half_w) & (np.abs(y - cy) <= half_w)
    in_guide = in_z_guide | in_x_guide
    eps_r = np.where(in_guide, 6.0, 1.0).astype(np.float32)
    data[:, :, :, 3] = eps_r

    z_inj = size // 8
    sigma_z = max(2.0, size / 16.0)
    k = 2.0 * np.pi / max(4.0, size / 5.0)
    z_env = np.exp(-0.5 * ((z - z_inj) / sigma_z) ** 2)
    lateral = np.exp(-0.5 * ((x - cx) ** 2 + (y - cy) ** 2) / (half_w ** 2))
    Ez = (z_env * lateral * np.sin(k * z)).astype(np.float32)
    data[:, :, :, 2] = Ez
    return data

def init_em_negative_index_slab(size, rng):
    """A planar slab of metamaterial-like ε_r < 1 (mathematical curiosity:
    real metamaterials need both ε and μ negative to be left-handed; here
    we only have ε. Still produces unusual refraction — the wave entering
    the slab has elevated phase velocity, like wandering into a region
    where light "speeds up"). The slab spans full XY, occupies middle Z.
    A plane-wave pulse from the −Z face encounters the slab front face
    and partially reflects / transmits with anomalous wavefront curvature.
    """
    data = init_em_plane_wave(size, rng)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    z_lo = size // 2 - max(2, size // 10)
    z_hi = size // 2 + max(2, size // 10)
    in_slab = (z >= z_lo) & (z < z_hi)
    eps_r = np.where(in_slab, 0.4, 1.0).astype(np.float32)
    # ε_r = 0.4 → c_local = c/√0.4 ≈ 1.58·c (phase velocity > c is fine;
    # group velocity is still bounded by c in real dispersive media).
    data[:, :, :, 3] = eps_r
    return data

def init_em_waveguide(size, rng):
    """Dielectric slab waveguide: a square cross-section channel of
    high-ε_r runs along Z through the box. A plane-wave pulse injected
    at the −Z face couples into the guided mode and propagates along
    the channel; the surrounding vacuum (lower ε_r) confines the wave
    by total internal reflection — same mechanism as a fiber-optic
    cable.
    """
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    cx, cy = size / 2.0, size / 2.0
    half_w = max(2, size // 8)         # waveguide half-width in cells

    # Square cross-section, full Z extent.
    in_guide = (np.abs(x - cx) <= half_w) & (np.abs(y - cy) <= half_w)
    eps_r = np.where(in_guide, 6.0, 1.0).astype(np.float32)
    data[:, :, :, 3] = eps_r

    # Inject a tone at z = size/8: Ez × envelope along Z, confined to
    # the guide cross-section.
    z_inj = size // 8
    sigma_z = max(2.0, size / 16.0)
    k = 2.0 * np.pi / max(4.0, size / 5.0)
    z_env = np.exp(-0.5 * ((z - z_inj) / sigma_z) ** 2)
    lateral = np.exp(-0.5 * ((x - cx) ** 2 + (y - cy) ** 2) / (half_w ** 2))
    Ez_pulse = (z_env * lateral * np.sin(k * z)).astype(np.float32)
    data[:, :, :, 2] = Ez_pulse
    return data

def init_viscous_fingers(size, rng):
    """Saffman-Taylor planar geometry: invader injected at the y=0
    face displaces defender across the volume to a y=L drain.

    A planar interface with sub-voxel roughness seeds the fingering
    instability — at the bottom, a thin slab is fully saturated; just
    above it, micro-roughness in saturation breaks symmetry and lets
    the most-favoured wavelength of the linear instability take off.
    Permeability is heterogeneous (fixed at init) so that fast-flow
    channels emerge from real porosity differences rather than only
    from the dynamics' positive feedback.
    """
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]

    # Smooth invader slab at the bottom (y < L/16) with a perturbed
    # interface a few voxels above.
    inj_thickness = max(1, size // 16)
    interface_y = inj_thickness + 2
    roughness = _canonical_noise(size, rng, -1.0, 1.0) * 1.5  # ±1.5 voxels
    perturbed_iface = interface_y + roughness  # shape (size, size, size)
    sat = (1.0 / (1.0 + np.exp(np.clip((y - perturbed_iface) * 1.5,
                                        -20, 20)))).astype(np.float32)

    # Pressure: linear ramp from inject_p=1 at y=0 to 0 at y=L (good
    # initial guess — Jacobi sweep refines it).
    pressure = (1.0 - y.astype(np.float32) / float(size)).astype(np.float32)

    # Permeability: log-normal-ish heterogeneity around 0.5.
    raw = _canonical_noise(size, rng, -1.0, 1.0)
    perm = np.clip(0.55 + 0.35 * raw, 0.15, 1.0).astype(np.float32)
    # Force unit perm in the injector slab so the front starts fed
    # from a wide-open channel.
    perm[:inj_thickness, :, :] = 1.0

    data[:, :, :, 0] = sat
    data[:, :, :, 1] = pressure
    data[:, :, :, 2] = perm
    return data

def init_viscous_fingers_radial(size, rng):
    """Saffman-Taylor *radial* geometry: a small spherical invader bubble
    at the box centre is driven outward radially. The classic
    laboratory experiment for radial fingering — the front becomes
    morphologically unstable at a critical radius and tip-splits into
    a fractal pattern."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    c = size / 2.0
    r0 = max(2.0, size * 0.06)
    dist = np.sqrt((x - c)**2 + (y - c)**2 + (z - c)**2)
    sat = (1.0 / (1.0 + np.exp((dist - r0) * 1.5))).astype(np.float32)
    # Pressure: ~ -log(r) far field (Stokes), uniform inside the bubble.
    rr = np.maximum(dist, 1.0)
    pressure = (1.0 - np.log(rr) / np.log(max(2.0, size / 2.0)))
    pressure = np.clip(pressure, 0.0, 1.0).astype(np.float32)
    raw = _canonical_noise(size, rng, -1.0, 1.0)
    perm = np.clip(0.55 + 0.35 * raw, 0.15, 1.0).astype(np.float32)
    data[:, :, :, 0] = sat
    data[:, :, :, 1] = pressure
    data[:, :, :, 2] = perm
    return data

def init_viscous_fingers_dual(size, rng):
    """Two facing injectors on opposite faces: invader pushed in from
    y=0 AND y=L with a defender drain ring around the equator. Fingers
    from the two fronts race toward each other and either merge or
    interfere — useful for studying breakthrough dynamics."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    inj_thickness = max(1, size // 16)
    rough = _canonical_noise(size, rng, -1.0, 1.0) * 1.5
    sat = np.zeros((size, size, size), dtype=np.float32)
    yf = y.astype(np.float32)
    iface_lo = inj_thickness + 2 + rough
    iface_hi = (size - 1) - inj_thickness - 2 + rough
    sat += (1.0 / (1.0 + np.exp(np.clip((yf - iface_lo) * 1.5, -20, 20)))).astype(np.float32)
    sat += (1.0 / (1.0 + np.exp(np.clip((iface_hi - yf) * 1.5, -20, 20)))).astype(np.float32)
    sat = np.clip(sat, 0.0, 1.0)
    # Pressure: peak at both injectors → drains at mid-height.
    yc = float(size) / 2.0
    pressure = np.clip(1.0 - np.abs(yf - yc) / yc, 0.0, 1.0).astype(np.float32)
    raw = _canonical_noise(size, rng, -1.0, 1.0)
    perm = np.clip(0.55 + 0.35 * raw, 0.15, 1.0).astype(np.float32)
    perm[:inj_thickness, :, :] = 1.0
    perm[-inj_thickness:, :, :] = 1.0
    data[:, :, :, 0] = sat
    data[:, :, :, 1] = pressure
    data[:, :, :, 2] = perm
    return data

def init_viscous_fingers_layered(size, rng):
    """Planar bottom→top injection with horizontally-banded permeability
    (alternating high/low layers).  Fingers preferentially channel
    through the high-perm layers and stall in the low-perm ones —
    a textbook stratified-reservoir study."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    inj_thickness = max(1, size // 16)
    interface_y = inj_thickness + 2
    rough = _canonical_noise(size, rng, -1.0, 1.0) * 1.5
    perturbed = interface_y + rough
    yf = y.astype(np.float32)
    sat = (1.0 / (1.0 + np.exp(np.clip((yf - perturbed) * 1.5,
                                        -20, 20)))).astype(np.float32)
    pressure = (1.0 - yf / float(size)).astype(np.float32)
    # Banded permeability: 4 horizontal layers along Y.
    n_bands = 4
    band_h = max(1, size // n_bands)
    perm = np.full((size, size, size), 0.3, dtype=np.float32)
    for b in range(n_bands):
        if b % 2 == 0:
            ylo = b * band_h
            yhi = min(size, ylo + band_h)
            perm[:, ylo:yhi, :] = 0.9
    perm[:inj_thickness, :, :] = 1.0
    # Tiny noise on top so individual fingers can break out.
    perm += _canonical_noise(size, rng, -0.05, 0.05)
    perm = np.clip(perm, 0.15, 1.0)
    data[:, :, :, 0] = sat
    data[:, :, :, 1] = pressure
    data[:, :, :, 2] = perm
    return data

def init_fire(size, rng):
    """Fire: heterogeneous fuel terrain with clearings and ignition source.
    Uniform fuel produces a boring uniform wavefront. Real forests have
    clearings, dense stands, and undergrowth variation — the fire front
    breaks up, races through dense patches, stalls at clearings, and
    creates spotting where embers jump gaps."""
    from scipy.ndimage import gaussian_filter, zoom
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    fine_noise = _canonical_noise(size, rng, 0.0, 1.0)
    # Large-scale structure: clearings and dense patches
    cs = CANONICAL_INIT_SIZE
    coarse = rng.random((cs, cs, cs)).astype(np.float32)
    coarse = gaussian_filter(coarse, sigma=4.0)
    if size != cs:
        coarse = zoom(coarse, size / cs, order=1).astype(np.float32)
    coarse = (coarse - coarse.min()) / (coarse.max() - coarse.min() + 1e-8)
    for y_idx in range(size):
        frac = y_idx / float(size)
        # Vertical gradient: denser at bottom, thinner at top, but with
        # a 0.3 floor so the fire can sustain across the full volume
        # rather than burning out when it reaches the upper half.
        base = max(0.3, 1.0 - frac * 0.7)
        # Mix large-scale + fine-scale fuel structure
        fuel_layer = base * (coarse[:, y_idx, :] * 0.5 + fine_noise[:, y_idx, :] * 0.3 + 0.4)
        # Clearings: voids where coarse noise is low
        fuel_layer[coarse[:, y_idx, :] < 0.18] *= 0.2
        data[:, y_idx, :, 0] = np.clip(fuel_layer, 0.0, 1.0)
    data[:, :, :, 2] = 1.0  # oxygen everywhere
    # Ignition: hot zone near bottom-center large enough to start a
    # self-sustaining burn front. Earlier we used r=size//12 (3 voxels
    # at size=64) which dropped below the diffusion length and the
    # flame guttered to near-zero (audit: EXTINCT). r=size//6 gives a
    # well-coupled ignition that can ignite the surrounding fuel.
    c = size // 2
    r = max(4, size // 6)
    z, yy, x = np.mgrid[0:size, 0:size, 0:size]
    iy = size // 6
    dist = np.sqrt((x - c)**2 + (yy - iy)**2 + (z - c)**2)
    data[:, :, :, 1] = np.where(dist < r, 1.0, 0.0).astype(np.float32)
    return data


def init_fire_fluid(size, rng):
    """Fire (fluid version): pair-1 channel layout (T, soot, ember, fuel).

    Same fuel-terrain logic as init_fire but rearranged to feed the new
    multi-pass fire pipeline (fire_chem_3d / fire_flow_3d).  Oxygen lives
    in pair 2 and is initialised separately by the `fire_oxygen`
    field2_init.

    Layout:
        R = temperature  (1.0 in a hot ignition ball near bottom-centre)
        G = soot         (starts at 0)
        B = ember        (starts at 0)
        A = fuel         (heterogeneous terrain)
    """
    from scipy.ndimage import gaussian_filter, zoom
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    fine_noise = _canonical_noise(size, rng, 0.0, 1.0)
    cs = CANONICAL_INIT_SIZE
    coarse = rng.random((cs, cs, cs)).astype(np.float32)
    coarse = gaussian_filter(coarse, sigma=4.0)
    if size != cs:
        coarse = zoom(coarse, size / cs, order=1).astype(np.float32)
    coarse = (coarse - coarse.min()) / (coarse.max() - coarse.min() + 1e-8)
    fuel = np.zeros((size, size, size), dtype=np.float32)
    for y_idx in range(size):
        frac = y_idx / float(size)
        base = max(0.3, 1.0 - frac * 0.7)
        layer = base * (coarse[:, y_idx, :] * 0.5
                        + fine_noise[:, y_idx, :] * 0.3 + 0.4)
        layer[coarse[:, y_idx, :] < 0.18] *= 0.2
        fuel[:, y_idx, :] = np.clip(layer, 0.0, 1.0)
    data[..., 3] = fuel  # A = fuel

    # Ignition: hot ball near bottom-centre.
    c = size // 2
    r = max(4, size // 6)
    z, yy, x = np.mgrid[0:size, 0:size, 0:size]
    iy = size // 6
    dist = np.sqrt((x - c) ** 2 + (yy - iy) ** 2 + (z - c) ** 2)
    data[..., 0] = np.where(dist < r, 1.0, 0.0).astype(np.float32)  # R = T
    return data


def init_fire_fluid_sparse(size, rng):
    """Fire (fluid, sparse): scattered fuel patches + bottom-centre spark."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]

    fuel = np.zeros((size, size, size), dtype=np.float64)
    n_patches = rng.randint(8, 16)
    for _ in range(n_patches):
        fx = rng.uniform(0.1, 0.9) * size
        fy = rng.uniform(0.05, 0.85) * size
        fz = rng.uniform(0.1, 0.9) * size
        rad = rng.uniform(0.06, 0.14) * size
        d2 = (x - fx) ** 2 + (y - fy) ** 2 + (z - fz) ** 2
        fuel += rng.uniform(0.5, 0.9) * np.exp(-0.5 * d2 / rad ** 2)
    data[..., 3] = np.clip(fuel, 0, 1).astype(np.float32)  # A = fuel

    # Spark at bottom-centre.
    ic = size // 2
    for dx in range(-2, 3):
        for dz in range(-2, 3):
            ix, iz = ic + dx, ic + dz
            if 0 <= ix < size and 0 <= iz < size:
                data[iz, 1, ix, 0] = 1.0  # R = T
    return data

def init_physarum(size, rng):
    """Physarum (adaptive flux network).

    Layout for the new `physarum_adaptive_3d` rule:
        R = trail (visualisation, |Q|)            — start 0
        G = conductivity ρ                        — small uniform + halos
        B = food sources (pressure boundary)      — sparse blobs
        A = pressure                              — start 0 (relaxes)

    A small but non-zero ρ baseline is essential: ρ acts as the
    diffusion coefficient for the pressure equation; all-zero ρ would
    leave pressure stuck and no flow could form.
    """
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]

    # ---- Food sources (B channel = pressure boundary condition) ----
    n_food = rng.randint(3, 7)
    food_centers = []
    for _ in range(n_food):
        fx = rng.uniform(0.15, 0.85) * size
        fy = rng.uniform(0.15, 0.85) * size
        fz = rng.uniform(0.15, 0.85) * size
        fr = rng.uniform(0.05, 0.10) * size
        food_centers.append((fx, fy, fz, fr))
        dist = np.sqrt((x - fx)**2 + (y - fy)**2 + (z - fz)**2)
        data[:, :, :, 2] += np.where(dist < fr, 1.0, 0.0).astype(np.float32)
    data[:, :, :, 2] = np.clip(data[:, :, :, 2], 0.0, 1.0)

    # ---- Conductivity ρ (G channel) ----
    # Small uniform baseline so the pressure solve has something to work
    # with everywhere; halos around food so initial tubes nucleate
    # sensibly toward each source.
    data[:, :, :, 1] = 0.04
    for fx, fy, fz, fr in food_centers:
        dist = np.sqrt((x - fx)**2 + (y - fy)**2 + (z - fz)**2)
        halo = np.exp(-0.5 * (dist / (fr * 2.0))**2).astype(np.float32)
        data[:, :, :, 1] += halo * 0.15
    data[:, :, :, 1] = np.clip(data[:, :, :, 1], 0.0, 1.0)

    return data

def init_physarum_two_source(size, rng):
    """Two food sources on opposite faces — the classic shortest-path
    optimisation problem (Tokyo-rail-network experiment style). The
    network should converge to a single thick tube connecting them."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    fr = max(2.0, size * 0.07)
    centers = [
        (size * 0.15, size * 0.5, size * 0.5),
        (size * 0.85, size * 0.5, size * 0.5),
    ]
    food = np.zeros((size, size, size), dtype=np.float32)
    for fx, fy, fz in centers:
        d = np.sqrt((x - fx)**2 + (y - fy)**2 + (z - fz)**2)
        food += np.where(d < fr, 1.0, 0.0).astype(np.float32)
    data[:, :, :, 2] = np.clip(food, 0.0, 1.0)
    data[:, :, :, 1] = 0.04
    for fx, fy, fz in centers:
        d = np.sqrt((x - fx)**2 + (y - fy)**2 + (z - fz)**2)
        data[:, :, :, 1] += np.exp(-0.5 * (d / (fr * 2.0))**2).astype(np.float32) * 0.20
    data[:, :, :, 1] = np.clip(data[:, :, :, 1], 0.0, 1.0)
    return data

def init_physarum_grid(size, rng):
    """3×3×3 lattice of food sources — forces the network to grow a
    real Steiner-tree-like structure instead of one straight tube,
    revealing redundant-path pruning behaviour."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    fr = max(1.5, size * 0.04)
    n = 3
    food = np.zeros((size, size, size), dtype=np.float32)
    halo = np.zeros((size, size, size), dtype=np.float32)
    for ix in range(n):
        for iy in range(n):
            for iz in range(n):
                fx = size * (ix + 1) / (n + 1)
                fy = size * (iy + 1) / (n + 1)
                fz = size * (iz + 1) / (n + 1)
                d = np.sqrt((x - fx)**2 + (y - fy)**2 + (z - fz)**2)
                food += (d < fr).astype(np.float32)
                halo += np.exp(-0.5 * (d / (fr * 2.0))**2).astype(np.float32)
    data[:, :, :, 2] = np.clip(food, 0.0, 1.0)
    data[:, :, :, 1] = np.clip(0.04 + halo * 0.10, 0.0, 1.0)
    return data

def init_physarum_ring(size, rng):
    """Food sources arranged on a ring — the network should form a
    circular highway with internal shortcut chords pruning over time."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    cx = cy = cz = size / 2.0
    R = size * 0.32
    fr = max(1.5, size * 0.05)
    n = 8
    food = np.zeros((size, size, size), dtype=np.float32)
    halo = np.zeros((size, size, size), dtype=np.float32)
    for k in range(n):
        ang = 2.0 * np.pi * k / n
        fx = cx + R * np.cos(ang)
        fy = cy + R * np.sin(ang)
        fz = cz
        d = np.sqrt((x - fx)**2 + (y - fy)**2 + (z - fz)**2)
        food += (d < fr).astype(np.float32)
        halo += np.exp(-0.5 * (d / (fr * 2.0))**2).astype(np.float32)
    data[:, :, :, 2] = np.clip(food, 0.0, 1.0)
    data[:, :, :, 1] = np.clip(0.04 + halo * 0.12, 0.0, 1.0)
    return data

def init_fracture(size, rng):
    """Fracture: compact tension specimen with grain structure and edge notch.
    A center-crack with random stress is just inverted crystal growth.
    Real fracture has: (1) grain boundaries — weak paths cracks prefer to
    follow, (2) edge notch like a CT specimen — stress concentrates at the
    tip via 1/√r singularity, (3) applied tensile load from boundaries,
    not random noise. This produces branching cracks along grain boundaries,
    distinctly different from crystal growth."""
    from scipy.ndimage import zoom
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    cs = CANONICAL_INIT_SIZE
    # Channel 2 = integrity: 1.0 with weakened grain boundaries
    # Voronoi grain structure — cracks preferentially follow boundaries
    n_grains = rng.randint(20, 40)
    grain_pts = rng.uniform(0, cs, (n_grains, 3))
    zz, yy, xx = np.mgrid[0:cs, 0:cs, 0:cs]
    min_dist1 = np.full((cs, cs, cs), 1e9)
    min_dist2 = np.full((cs, cs, cs), 1e9)
    for gp in grain_pts:
        d = np.sqrt((xx - gp[0])**2 + (yy - gp[1])**2 + (zz - gp[2])**2)
        new_min2 = np.where(d < min_dist1, min_dist1, np.minimum(min_dist2, d))
        min_dist1 = np.minimum(min_dist1, d)
        min_dist2 = new_min2
    # Sharp Voronoi boundaries: integrity dips where d1 ≈ d2
    boundary = np.exp(-((min_dist2 - min_dist1) * 2.0)**2).astype(np.float32)
    if size != cs:
        boundary = zoom(boundary, size / cs, order=1).astype(np.float32)
    data[:, :, :, 2] = 1.0 - boundary * 0.15  # grain boundaries at 85% integrity
    # Edge notch: V-shaped notch from -X face (compact tension specimen)
    c = size // 2
    notch_depth = max(3, size // 6)
    notch_w = max(1, size // 24)
    for xi in range(notch_depth):
        # Notch tapers to a point → stress concentrator at tip
        width = max(1, int(notch_w * (1.0 - xi / notch_depth)))
        y_lo, y_hi = max(0, c - width), min(size, c + width + 1)
        z_lo, z_hi = max(0, c - width), min(size, c + width + 1)
        data[z_lo:z_hi, y_lo:y_hi, xi, 2] = 0.0
    # Channel 1 = stress: tensile load (mode I) + crack-tip concentration
    z_g, y_g, x_g = np.mgrid[0:size, 0:size, 0:size]
    # Applied tension: pulls Y-faces apart (increases near top/bottom)
    y_norm = (y_g - c).astype(np.float64) / max(c, 1)
    tension = np.abs(y_norm) * 0.15
    # 1/√r stress singularity at notch tip (classic fracture mechanics, clamped)
    tip_dist = np.sqrt((x_g - notch_depth)**2 + (y_g - c)**2 + (z_g - c)**2).astype(np.float64)
    stress_conc = 0.5 / np.sqrt(np.maximum(tip_dist, 1.0) / size)
    data[:, :, :, 1] = np.clip(tension + stress_conc * 0.2, 0.0, 0.5).astype(np.float32)
    return data

def init_fracture_peridyn(size, rng):
    """Peridynamic fracture init: quasi-static pre-load with edge notch.

    Layout for `peridyn_disp_3d` rule:
        R = u_x = 0
        G = u_y  (linear strain ramp from -load at y=0 to +load at y=L)
        B = u_z = 0
        A = integrity ∈ {0,1}

    A V-shaped through-thickness edge notch from the −X face into the
    centre acts as a stress concentrator (1/√r in linear elasticity).
    Imposing the linear-strain field as the *initial* condition skips
    the elastic-wave loading transient — the medium starts in static
    equilibrium far from the notch, and the geometric stress
    concentration breaks bonds at the notch tip first.  The crack
    then propagates because as bonds break the load is redistributed
    onto the new tip — the textbook brittle-fracture mechanism.
    """
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]

    # Pre-loaded linear strain field. With load=0.5 and L=48,
    # bulk strain ≈ 2 · 0.5 / 43 ≈ 0.023 — well below s_crit=0.05,
    # so the bulk is sub-critical.  Stress concentration at the
    # notch tip (≈3× in linear elasticity, similar in peridynamics)
    # locally raises the stretch above critical, breaking the
    # tip-most bonds first — then the crack propagates because
    # each newly-broken bond redistributes load onto the next.
    load = 0.5
    slab = max(1, size // 24)
    inner_lo = float(slab)
    inner_hi = float(size - slab - 1)
    inner_extent = max(1.0, inner_hi - inner_lo)
    yf = y.astype(np.float32)
    # Linear ramp inside the bulk; clamp the ends to ±load to match
    # the disp pass's hard-set grip displacement.
    t = np.clip((yf - inner_lo) / inner_extent, 0.0, 1.0)
    u_y_field = (-load + 2.0 * load * t).astype(np.float32)

    # Tiny noise to break perfect symmetry — kept much smaller than
    # the gap between bulk strain (~0.054) and s_crit (0.06).
    u_y_field += _canonical_noise(size, rng, -0.001, 0.001)

    integrity = np.ones((size, size, size), dtype=np.float32)

    # Edge notch: V-shape from −X face into the bulk, centred on
    # y = size/2.
    c = size // 2
    notch_depth = max(3, size // 6)
    notch_w = max(1, size // 24)
    for xi in range(notch_depth):
        w = max(1, int(notch_w * (1.0 - xi / notch_depth)))
        integrity[:, c - w:c + w + 1, xi] = 0.0

    # Sub-percolation random weakening: just 0.1% of cells damaged.
    # Random damage seeds micro-branching but every broken cell
    # concentrates stress on its 26 neighbours (each bond now carries
    # roughly N/(N-1) more force) so a high density cascades the
    # whole bulk into failure.  Keep it sparse.
    weak = rng.random((size, size, size)) < 0.001
    integrity[weak] = 0.0

    # Grip slabs MUST stay intact — they're the loaded boundary.
    integrity[:, :slab, :] = 1.0
    integrity[:, -slab:, :] = 1.0

    data[:, :, :, 1] = u_y_field
    data[:, :, :, 3] = integrity
    return data


def _peridyn_preload(size, rng, load=0.5):
    """Helper: return (u_y_field, slab) with a pre-loaded linear strain
    matching displacement-controlled grip BCs at y = ±slab faces."""
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    slab = max(1, size // 24)
    inner_lo = float(slab)
    inner_hi = float(size - slab - 1)
    inner_extent = max(1.0, inner_hi - inner_lo)
    yf = y.astype(np.float32)
    t = np.clip((yf - inner_lo) / inner_extent, 0.0, 1.0)
    u_y = (-load + 2.0 * load * t).astype(np.float32)
    u_y += _canonical_noise(size, rng, -0.001, 0.001)
    return u_y, slab


def init_fracture_double_notch(size, rng):
    """Two facing edge notches on −X and +X faces. The two crack tips
    race toward each other under tensile load — they typically curve
    slightly to meet, producing a non-coplanar mode-I+II ligament
    failure rather than a single straight Mode-I crack."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    u_y, slab = _peridyn_preload(size, rng, load=0.5)
    integrity = np.ones((size, size, size), dtype=np.float32)
    c = size // 2
    notch_depth = max(3, size // 6)
    notch_w = max(1, size // 24)
    for xi in range(notch_depth):
        w = max(1, int(notch_w * (1.0 - xi / notch_depth)))
        # −X face notch
        integrity[:, c - w:c + w + 1, xi] = 0.0
        # +X face notch (mirror)
        integrity[:, c - w:c + w + 1, size - 1 - xi] = 0.0
    weak = rng.random((size, size, size)) < 0.001
    integrity[weak] = 0.0
    integrity[:, :slab, :] = 1.0
    integrity[:, -slab:, :] = 1.0
    data[:, :, :, 1] = u_y
    data[:, :, :, 3] = integrity
    return data


def init_fracture_penny_crack(size, rng):
    """Internal penny-shaped crack on the z-midplane: a thin disc of
    broken bonds in the bulk with no surface contact. Loading drives
    Mode-I opening and the crack ring grows radially outward — the
    canonical 3D fracture mechanics test geometry."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    u_y, slab = _peridyn_preload(size, rng, load=0.5)
    integrity = np.ones((size, size, size), dtype=np.float32)
    c = size / 2.0
    crack_radius = max(2.0, size * 0.18)
    in_plane = (np.abs(y - c) < 1.5)
    in_disc = ((x - c)**2 + (z - c)**2 < crack_radius**2)
    integrity[in_plane & in_disc] = 0.0
    weak = rng.random((size, size, size)) < 0.0005
    integrity[weak] = 0.0
    integrity[:, :slab, :] = 1.0
    integrity[:, -slab:, :] = 1.0
    data[:, :, :, 1] = u_y
    data[:, :, :, 3] = integrity
    return data


def init_fracture_shear(size, rng):
    """Mode-II shear loading: linear u_x ramp along Y instead of u_y.
    The −X edge notch tip now experiences in-plane shear, producing
    a slanted crack that propagates at ~45° to the loading axis
    (the maximum-tensile-stress direction in pure shear)."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    load = 0.5
    slab = max(1, size // 24)
    inner_lo = float(slab)
    inner_hi = float(size - slab - 1)
    inner_extent = max(1.0, inner_hi - inner_lo)
    yf = y.astype(np.float32)
    t = np.clip((yf - inner_lo) / inner_extent, 0.0, 1.0)
    # Shear: u_x grows linearly with y
    u_x = (-load + 2.0 * load * t).astype(np.float32)
    u_x += _canonical_noise(size, rng, -0.001, 0.001)
    integrity = np.ones((size, size, size), dtype=np.float32)
    c = size // 2
    notch_depth = max(3, size // 6)
    notch_w = max(1, size // 24)
    for xi in range(notch_depth):
        w = max(1, int(notch_w * (1.0 - xi / notch_depth)))
        integrity[:, c - w:c + w + 1, xi] = 0.0
    weak = rng.random((size, size, size)) < 0.001
    integrity[weak] = 0.0
    integrity[:, :slab, :] = 1.0
    integrity[:, -slab:, :] = 1.0
    data[:, :, :, 0] = u_x
    data[:, :, :, 3] = integrity
    return data


def init_fracture_pre_damaged(size, rng):
    """No notch, but a denser field of random pre-damage (~1%). With
    enough seeds and a moderate load the cracks self-organise into a
    branching, percolating fracture network — qualitatively different
    from the single-tip propagation of the notched specimen."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    u_y, slab = _peridyn_preload(size, rng, load=0.5)
    integrity = np.ones((size, size, size), dtype=np.float32)
    weak = rng.random((size, size, size)) < 0.012
    integrity[weak] = 0.0
    integrity[:, :slab, :] = 1.0
    integrity[:, -slab:, :] = 1.0
    data[:, :, :, 1] = u_y
    data[:, :, :, 3] = integrity
    return data


def init_galaxy(size, rng):
    """Galaxy: low-amplitude perturbations on a uniform background.
    Seeds the Jeans instability — collapse takes a few hundred steps to
    become visible.  For a stronger initial cosmic-web structure prefer
    the `galaxy_filaments` variant (now the preset default)."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    # Density: 0.1 baseline + spatially-correlated perturbations big
    # enough to seed Jeans collapse within a few hundred timesteps.
    # The legacy ±0.05 white-noise init was too small-wavelength for
    # gravity to amplify before pressure smoothed it out.
    from scipy.ndimage import gaussian_filter
    pert = _canonical_noise(size, rng, -1.0, 1.0).astype(np.float32)
    pert = gaussian_filter(pert, sigma=2.0)
    pert *= 0.06 / max(np.std(pert), 1e-6)
    data[:, :, :, 0] = np.clip(0.1 + pert, 0.005, None)
    # Velocity: tiny random seed.
    data[:, :, :, 1] = _canonical_noise(size, rng, -0.005, 0.005)
    data[:, :, :, 2] = _canonical_noise(size, rng, -0.005, 0.005)
    data[:, :, :, 3] = _canonical_noise(size, rng, -0.005, 0.005)
    return data

def init_lichen(size, rng):
    """Lichen: three competing species with scattered seeds on a resource field."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    # Channel 2 = resource: starts nearly full
    data[:, :, :, 2] = _canonical_noise(size, rng, 0.7, 1.0)
    # Channel 0 = species A (pioneer): scattered seeds
    noise_a = _canonical_noise(size, rng, 0.0, 1.0)
    data[:, :, :, 0] = np.where(noise_a > 0.94, 0.5, 0.0).astype(np.float32)
    # Channel 1 = species B (competitor): fewer, different locations
    noise_b = _canonical_noise(size, rng, 0.0, 1.0)
    data[:, :, :, 1] = np.where(noise_b > 0.96, 0.5, 0.0).astype(np.float32)
    # Channel 3 = species C (nomad): rarest
    noise_c = _canonical_noise(size, rng, 0.0, 1.0)
    data[:, :, :, 3] = np.where(noise_c > 0.97, 0.5, 0.0).astype(np.float32)
    return data


# ── Structured init variants ────────────────────────────────────────
# These create spatially organized initial conditions that seed specific
# dynamics: pursuit waves, Turing spots, spiral defects, grain boundaries,
# erosion channels, etc.  Used by search via init_variants.

def init_predator_prey_separated(size, rng):
    """Prey in one hemisphere, predators in the opposite → pursuit chase dynamics.
    Spatial separation forces migration → traveling waves, not static coexistence."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]

    # Random dividing plane through center
    theta = rng.uniform(0, 2 * np.pi)
    phi = rng.uniform(-np.pi / 4, np.pi / 4)
    nx = np.cos(phi) * np.cos(theta)
    ny = np.cos(phi) * np.sin(theta)
    nz = np.sin(phi)
    mid = size / 2.0
    signed_dist = (x - mid) * nx + (y - mid) * ny + (z - mid) * nz

    # Prey concentrated on positive side, predators on negative
    prey = np.where(signed_dist > 0, 0.9, 0.05).astype(np.float32)
    predator = np.where(signed_dist < 0, 0.5, 0.01).astype(np.float32)

    # Smooth the boundary (3-cell transition zone)
    transition = np.exp(-0.5 * (signed_dist / max(size * 0.05, 1.5))**2).astype(np.float32)
    prey = prey * (1 - transition * 0.5) + transition * 0.4
    predator = predator * (1 - transition * 0.3) + transition * 0.2

    # Add noise for symmetry breaking
    prey += _canonical_noise(size, rng, -0.03, 0.03)
    predator += _canonical_noise(size, rng, -0.02, 0.02)

    data[:, :, :, 0] = np.clip(prey, 0.01, 1.0)
    data[:, :, :, 1] = np.clip(predator, 0.0, 1.0)
    return data


def init_morphogen_hotspots(size, rng):
    """High activator in a few hotspots, low everywhere else → Turing patterns
    grow outward from nucleation sites instead of competing everywhere at once."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]

    # Low baseline activator and inhibitor
    data[:, :, :, 0] = 0.05  # activator low
    data[:, :, :, 1] = 0.01  # inhibitor very low
    data[:, :, :, 2] = 0.5   # tissue density

    # Place 4-10 activator hotspots
    n_spots = rng.randint(4, 11)
    for _ in range(n_spots):
        cx = rng.uniform(0.1, 0.9) * size
        cy = rng.uniform(0.1, 0.9) * size
        cz = rng.uniform(0.1, 0.9) * size
        r = rng.uniform(max(1.5, size * 0.03), size * 0.08)
        amp = rng.uniform(0.3, 0.8)
        dist = np.sqrt((x - cx)**2 + (y - cy)**2 + (z - cz)**2)
        data[:, :, :, 0] += (amp * np.exp(-0.5 * (dist / r)**2)).astype(np.float32)

    data[:, :, :, 0] = np.clip(data[:, :, :, 0], 0.01, 5.0)
    # Tiny noise for secondary instability
    data[:, :, :, 0] += _canonical_noise(size, rng, -0.005, 0.005)
    data[:, :, :, 0] = np.clip(data[:, :, :, 0], 0.01, 5.0)
    return data


def init_bz_spiral_seed(size, rng):
    """Engineered phase singularity → spiral/scroll waves form immediately.
    Phase winds 0→2π around a central axis, creating the topological defect
    that seeds scroll wave dynamics in BZ/CGLE."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    mid = size / 2.0

    # Choose a random axis for the scroll wave
    axis = rng.randint(0, 3)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]

    if axis == 0:
        dx, dy = (x - mid).astype(np.float64), (y - mid).astype(np.float64)
    elif axis == 1:
        dx, dy = (x - mid).astype(np.float64), (z - mid).astype(np.float64)
    else:
        dx, dy = (y - mid).astype(np.float64), (z - mid).astype(np.float64)

    # Phase = angle around axis (creates 2π winding = topological defect)
    phase = np.arctan2(dy, dx)  # [-π, π]
    # Add a second singularity offset from center for richer dynamics
    off = rng.uniform(0.15, 0.35) * size
    angle = rng.uniform(0, 2 * np.pi)
    cx2 = mid + off * np.cos(angle)
    cy2 = mid + off * np.sin(angle)
    if axis == 0:
        dx2, dy2 = x - cx2, y - cy2
    elif axis == 1:
        dx2, dy2 = x - cx2, z - cy2
    else:
        dx2, dy2 = y - cx2, z - cy2
    phase2 = np.arctan2(dy2.astype(np.float64), dx2.astype(np.float64))
    # Combine: two counter-rotating spirals
    combined_phase = phase + phase2

    # Amplitude near limit cycle
    amp = 1.0 + _canonical_noise(size, rng, -0.05, 0.05)

    data[:, :, :, 0] = (amp * np.cos(combined_phase)).astype(np.float32)
    data[:, :, :, 1] = (amp * np.sin(combined_phase)).astype(np.float32)
    data[:, :, :, 2] = ((combined_phase / (2 * np.pi)) % 1.0).astype(np.float32)
    return data


def init_bz_scroll_filament(size, rng):
    """Barkley scroll-wave seed: Winfree broken-wavefront recipe.

    A planar excitation that abruptly TERMINATES inside the box
    creates a phase-singularity line along the termination edge.
    The wave can't propagate into the recovery zone but can curl
    around the broken end → 1-D scroll filament along the axis of
    the discontinuity.

    Layout for `bz_scroll_3d` rule:
        R = activator u ∈ [0, 1]    (excited slab terminating mid-box)
        G = inhibitor v ∈ [0, 1]    (refractory tail just behind front)
        B = filament strength       (start 0; rule fills it in)
        A = phase                   (start 0)

    Two perpendicular broken fronts produce two intersecting scroll
    filaments that twist, knot, and (for break-up parameters) cascade
    into the spaghetti-defect regime.
    """
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    L = float(size)

    # ---- Broken front #1: filament along z-axis ----
    # Wave occupies y > L/2 AND x in [L/3, 2L/3].
    # Tail (refractory) immediately behind: y > L/2 AND x in [L/3-w, L/3].
    front1 = ((y > L / 2) & (x >= L / 3) & (x <= 2 * L / 3))
    tail1  = ((y > L / 2) & (x >= L / 3 - 4) & (x < L / 3))

    # ---- Broken front #2: filament along x-axis (perpendicular) ----
    front2 = ((z > L / 2) & (y >= L / 3) & (y <= 2 * L / 3) & (x < L / 2))
    tail2  = ((z > L / 2) & (y >= L / 3 - 4) & (y < L / 3) & (x < L / 2))

    u = np.where(front1 | front2, 1.0, 0.0).astype(np.float32)
    v = np.where(tail1 | tail2,  0.4, 0.0).astype(np.float32)
    # Smooth the tail so v is graded (helps the rule's window catch the
    # filament cleanly).
    v += np.where(front1 | front2, 0.15, 0.0).astype(np.float32)

    # Tiny noise to help symmetry break and the second filament find
    # a spot to wander into.
    u = np.clip(u + _canonical_noise(size, rng, -0.02, 0.02), 0.0, 1.0)
    v = np.clip(v + _canonical_noise(size, rng, -0.02, 0.02), 0.0, 1.0)

    data[:, :, :, 0] = u.astype(np.float32)
    data[:, :, :, 1] = v.astype(np.float32)
    return data


def init_crystal_multi_seed(size, rng):
    """Multiple competing crystal nucleation sites → grain boundaries form
    where growing crystals collide. Each seed gets a random crystallographic
    orientation packed into the B channel; the crystal_growth shader rotates
    its β kernel by that angle so every grain's facets point along its own
    axes. When two grains meet their orientations clash → visible sharp
    grain boundary, just like in real polycrystalline metal etchings."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)

    # Supersaturation field (limited reservoir, see init_crystal_seed)
    data[:, :, :, 1] = 0.25

    # 3-7 seeds at random positions
    n_seeds = rng.randint(3, 8)
    r = max(1.0, size * 0.02)
    _stamp_crystal_seeds(data, rng, n_seeds, r, edge_pad=0.1)
    return data


def init_crystal_polycrystal(size, rng):
    """Dense polycrystalline aggregate: many small seeds packed close together,
    each with its own random crystallographic orientation. Grains grow until
    they collide, leaving a network of grain boundaries where orientation
    discontinuities lock in. This is the canonical metallurgy texture —
    looks like an etched metal cross-section under an optical microscope.

    Best viewed with the B (Orientation) channel in HSV/cyclic colour mode
    so each grain reads as a different hue."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    data[:, :, :, 1] = 0.25  # limited supersaturation reservoir
    # Many small seeds — enough that the melt fills with grain boundaries
    # before any single grain becomes visually dominant. Seed count scales
    # with grid volume so the grain density stays roughly constant across
    # different grid sizes.
    n_seeds = max(20, int((size / 32) ** 3 * 12))
    r = max(1.0, size * 0.012)
    _stamp_crystal_seeds(data, rng, n_seeds, r, edge_pad=0.05)
    return data


def _stamp_crystal_seeds(data, rng, n_seeds, r, edge_pad):
    """Paint n spherical crystal seeds into ``data`` (R=phase, G=supersat,
    B=orient). Each seed touches only a small box around its centre so
    cost is O(n_seeds * r^3) instead of O(n_seeds * size^3) -- the previous
    full-grid sqrt+where formulation took ~6 GFLOP at size 128 with the
    polycrystal seed count, dominating load time."""
    size = data.shape[0]
    r_int = int(np.ceil(r)) + 1  # +1 for safety on the upper boundary check

    # Vectorised generation of all seed centres / orientations at once
    centres = rng.uniform(edge_pad, 1.0 - edge_pad, size=(n_seeds, 3)) * size
    orients = rng.uniform(0.0, 1.0, size=n_seeds).astype(np.float32)
    r_sq = r * r

    for i in range(n_seeds):
        cx, cy, cz = centres[i]
        # Bounding box clamped to the grid
        x_lo = max(0, int(cx) - r_int);  x_hi = min(size, int(cx) + r_int + 1)
        y_lo = max(0, int(cy) - r_int);  y_hi = min(size, int(cy) + r_int + 1)
        z_lo = max(0, int(cz) - r_int);  z_hi = min(size, int(cz) + r_int + 1)
        if x_lo >= x_hi or y_lo >= y_hi or z_lo >= z_hi:
            continue
        # Local distance field (one box per seed instead of one full grid)
        zs = np.arange(z_lo, z_hi, dtype=np.float32) - cz
        ys = np.arange(y_lo, y_hi, dtype=np.float32) - cy
        xs = np.arange(x_lo, x_hi, dtype=np.float32) - cx
        dz2 = (zs * zs)[:, None, None]
        dy2 = (ys * ys)[None, :, None]
        dx2 = (xs * xs)[None, None, :]
        mask = (dz2 + dy2 + dx2) < r_sq
        if not mask.any():
            continue
        # In-place writes into the bounded slab. Later seeds OVERWRITE
        # earlier ones inside their own box -- same behaviour as the
        # original full-grid np.where chain since seeds are painted
        # in the same order.
        slab_phi   = data[z_lo:z_hi, y_lo:y_hi, x_lo:x_hi, 0]
        slab_super = data[z_lo:z_hi, y_lo:y_hi, x_lo:x_hi, 1]
        slab_orient= data[z_lo:z_hi, y_lo:y_hi, x_lo:x_hi, 2]
        slab_phi[mask]    = 1.0
        slab_super[mask]  = 0.0
        slab_orient[mask] = orients[i]


def init_erosion_ridges(size, rng):
    """Terrain with ridges, valleys, and pre-carved channels → water concentrates
    along existing weak points → feedback loops (deeper flow → faster erosion)."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z_grid, y_grid, x_grid = np.mgrid[0:size, 0:size, 0:size]

    # Height field with ridges (low-freq sine waves)
    n_ridges = rng.randint(2, 5)
    height = np.zeros((size, size), dtype=np.float32)
    for _ in range(n_ridges):
        angle = rng.uniform(0, np.pi)
        freq = rng.uniform(0.5, 2.0)
        amp = rng.uniform(0.1, 0.3)
        height += amp * np.sin(freq * 2 * np.pi *
            (x_grid[0, 0, :, np.newaxis] * np.cos(angle)
             + z_grid[0, :, 0, np.newaxis].T * np.sin(angle)) / size)

    # Normalize height to [0.3, 0.8] of grid
    height = 0.3 + 0.5 * (height - height.min()) / max(height.max() - height.min(), 0.01)
    terrain_top = (height * size).astype(int)

    # Fill solid below terrain surface
    for yi in range(size):
        for zi in range(size):
            h = min(terrain_top[zi, yi], size - 2)
            data[zi, :h, yi, 0] = 1.0

    # Cut 1-3 channels (pre-carved valleys)
    n_channels = rng.randint(1, 4)
    for _ in range(n_channels):
        ch_z = rng.randint(size // 4, 3 * size // 4)
        ch_width = rng.randint(max(1, size // 16), max(2, size // 8))
        ch_depth = rng.randint(max(1, size // 8), max(2, size // 4))
        z_lo = max(0, ch_z - ch_width)
        z_hi = min(size, ch_z + ch_width)
        for zi in range(z_lo, z_hi):
            for yi in range(size):
                h = min(terrain_top[zi, yi], size - 2)
                carve_top = max(0, h - ch_depth)
                for y_v in range(carve_top, h):
                    data[zi, y_v, yi, 0] = 0.0

    # Water source at top
    data[:, -2:, :, 1] = 0.8
    # Add some water in channels too
    data[:, :, :, 1] = np.where(
        (data[:, :, :, 0] < 0.5) & (y_grid < int(size * 0.5)),
        0.3, data[:, :, :, 1])
    return data


def init_flocking_vortex(size, rng):
    """Agents arranged in 2-4 initial vortex rings → immediate collective rotation
    instead of slow random alignment. Vortices interact, merge, or compete."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    mid = size / 2.0

    n_vortices = rng.randint(2, 5)
    for _ in range(n_vortices):
        # Vortex center
        cx = rng.uniform(0.2, 0.8) * size
        cy = rng.uniform(0.2, 0.8) * size
        cz = rng.uniform(0.2, 0.8) * size
        r_ring = rng.uniform(0.1, 0.25) * size
        r_tube = rng.uniform(0.04, 0.1) * size

        # Distance from ring center (in a random plane)
        dx = (x - cx).astype(np.float64)
        dy = (y - cy).astype(np.float64)
        dz = (z - cz).astype(np.float64)

        # Project onto ring plane (pick random axis)
        axis = rng.randint(0, 3)
        if axis == 0:
            r_from_axis = np.sqrt(dy**2 + dz**2)
            angle = np.arctan2(dz, dy)
            dist_from_ring = np.sqrt((r_from_axis - r_ring)**2 + dx**2)
        elif axis == 1:
            r_from_axis = np.sqrt(dx**2 + dz**2)
            angle = np.arctan2(dz, dx)
            dist_from_ring = np.sqrt((r_from_axis - r_ring)**2 + dy**2)
        else:
            r_from_axis = np.sqrt(dx**2 + dy**2)
            angle = np.arctan2(dy, dx)
            dist_from_ring = np.sqrt((r_from_axis - r_ring)**2 + dz**2)

        # Density concentrated around the ring
        density = 0.5 * np.exp(-0.5 * (dist_from_ring / r_tube)**2)
        data[:, :, :, 0] += density.astype(np.float32)

        # Tangential velocity (circular motion around the ring)
        speed = rng.uniform(0.1, 0.3)
        if axis == 0:
            data[:, :, :, 2] += (-density * np.sin(angle) * speed).astype(np.float32)
            data[:, :, :, 3] += ( density * np.cos(angle) * speed).astype(np.float32)
        elif axis == 1:
            data[:, :, :, 1] += (-density * np.sin(angle) * speed).astype(np.float32)
            data[:, :, :, 3] += ( density * np.cos(angle) * speed).astype(np.float32)
        else:
            data[:, :, :, 1] += (-density * np.sin(angle) * speed).astype(np.float32)
            data[:, :, :, 2] += ( density * np.cos(angle) * speed).astype(np.float32)

    data[:, :, :, 0] = np.clip(data[:, :, :, 0], 0, 1)
    return data


# ── New init variants for improved CA visual quality ──

def init_game_of_life_centered(size, rng):
    """Clustered population in center third — grows outward into empty space."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    lo = size // 3
    hi = 2 * size // 3
    cs = CANONICAL_INIT_SIZE
    # Generate at canonical res, extract center
    field = rng.random((cs, cs, cs)).astype(np.float32)
    from scipy.ndimage import zoom
    if size != cs:
        field = zoom(field, size / cs, order=0).astype(np.float32)
    # Only populate center third (density ~35%)
    center = field[lo:hi, lo:hi, lo:hi]
    data[lo:hi, lo:hi, lo:hi, 0] = (center < 0.35).astype(np.float32)
    return data


def init_smoothlife_sparse(size, rng):
    """A few smooth blobs in empty space — watch creatures nucleate and interact."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    n_blobs = rng.randint(4, 9)
    for _ in range(n_blobs):
        cx = rng.uniform(0.15, 0.85) * size
        cy = rng.uniform(0.15, 0.85) * size
        cz = rng.uniform(0.15, 0.85) * size
        rx = rng.uniform(0.05, 0.12) * size
        ry = rng.uniform(0.05, 0.12) * size
        rz = rng.uniform(0.05, 0.12) * size
        z, y, x = np.mgrid[0:size, 0:size, 0:size]
        d2 = ((x - cx) / rx)**2 + ((y - cy) / ry)**2 + ((z - cz) / rz)**2
        val = rng.uniform(0.4, 0.8) * np.exp(-0.5 * d2)
        data[:, :, :, 0] += val.astype(np.float32)
    data[:, :, :, 0] = np.clip(data[:, :, :, 0], 0.0, 1.0)
    return data


def init_gray_scott_worms_dense(size, rng):
    """Gray-Scott with dense V catalyst — worm patterns appear immediately."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    # U = 1 everywhere (substrate)
    data[:, :, :, 0] = 1.0
    # V = 0.25 baseline + noise — dense enough for immediate worm nucleation
    noise = _canonical_noise(size, rng, 0.0, 0.15)
    data[:, :, :, 1] = 0.25 + noise
    # Subtract catalyst from substrate
    data[:, :, :, 0] -= data[:, :, :, 1]
    return data


def init_lenia_multi_colocated(size, rng):
    """Multi-channel Lenia with co-located blobs — channels differentiate in place.
    Creates creatures with true internal structure (core/skin/metabolism)."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    n_blobs = rng.randint(3, 7)
    for _ in range(n_blobs):
        # Same center for all channels
        cx = rng.uniform(0.15, 0.85) * size
        cy = rng.uniform(0.15, 0.85) * size
        cz = rng.uniform(0.15, 0.85) * size
        z, y, x = np.mgrid[0:size, 0:size, 0:size]
        dx = x - cx
        dy = y - cy
        dz = z - cz

        for ch in range(3):
            # Each channel has slightly different shape
            rx = rng.uniform(0.06, 0.14) * size
            ry = rng.uniform(0.06, 0.14) * size
            rz = rng.uniform(0.06, 0.14) * size
            d2 = (dx / rx)**2 + (dy / ry)**2 + (dz / rz)**2
            amp = rng.uniform(0.3, 0.7)
            data[:, :, :, ch] += (amp * np.exp(-0.5 * d2)).astype(np.float32)

    data[:, :, :, :3] = np.clip(data[:, :, :, :3], 0.0, 1.0)
    return data


def init_kuramoto_clusters(size, rng):
    """Pre-formed phase-locked clusters — chimera states emerge as clusters compete."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    c = size / 2.0

    # 3-4 large phase-locked clusters at different spatial positions
    n_clusters = rng.randint(3, 5)
    phase_field = np.zeros((size, size, size), dtype=np.float64)
    weight_sum = np.zeros((size, size, size), dtype=np.float64) + 1e-10

    for i in range(n_clusters):
        cx = rng.uniform(0.2, 0.8) * size
        cy = rng.uniform(0.2, 0.8) * size
        cz = rng.uniform(0.2, 0.8) * size
        radius = rng.uniform(0.15, 0.3) * size
        target_phase = i / n_clusters  # evenly spaced phases [0,1)
        # Gaussian weight for this cluster
        d2 = (x - cx)**2 + (y - cy)**2 + (z - cz)**2
        w = np.exp(-0.5 * d2 / radius**2)
        phase_field += w * target_phase
        weight_sum += w

    phase_field /= weight_sum
    # Add small noise so clusters aren't perfectly locked
    phase_field += rng.uniform(0, 0.05, (size, size, size))
    data[:, :, :, 0] = (phase_field % 1.0).astype(np.float32)

    # Natural frequency: spatially varying (channel G)
    freq = _canonical_noise(size, rng, -0.5, 0.5)
    data[:, :, :, 1] = freq
    # Coherence starts near 1 within clusters
    data[:, :, :, 2] = np.clip(1.0 - 2.0 * rng.random((size, size, size)).astype(np.float32) * 0.3, 0, 1).astype(np.float32)
    return data


def init_galaxy_filaments(size, rng):
    """Pre-seeded cosmic web — density perturbations at Jeans wavelength
    so gravitational collapse is visible within ~50 steps."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    c = size / 2.0
    z, y, x = np.mgrid[0:size, 0:size, 0:size]

    # Baseline density
    base_density = 0.1
    density = np.full((size, size, size), base_density, dtype=np.float64)

    # Seed 3-5 overdense filament-like regions (sine waves in random directions)
    for _ in range(rng.randint(3, 6)):
        kx = rng.uniform(-0.15, 0.15)
        ky = rng.uniform(-0.15, 0.15)
        kz = rng.uniform(-0.15, 0.15)
        phase = rng.uniform(0, 2 * np.pi)
        amp = rng.uniform(0.02, 0.06)
        density += amp * np.cos(kx * x + ky * y + kz * z + phase)

    # Add 2-3 dense nodes (proto-cluster seeds)
    for _ in range(rng.randint(2, 4)):
        nx = rng.uniform(0.2, 0.8) * size
        ny = rng.uniform(0.2, 0.8) * size
        nz = rng.uniform(0.2, 0.8) * size
        r2 = (x - nx)**2 + (y - ny)**2 + (z - nz)**2
        sigma = rng.uniform(0.05, 0.1) * size
        density += 0.08 * np.exp(-0.5 * r2 / sigma**2)

    density = np.clip(density, 0.01, 0.5)
    data[:, :, :, 0] = density.astype(np.float32)
    # Small random velocities
    data[:, :, :, 1] = (rng.uniform(-0.005, 0.005, (size, size, size))).astype(np.float32)
    data[:, :, :, 2] = (rng.uniform(-0.005, 0.005, (size, size, size))).astype(np.float32)
    data[:, :, :, 3] = (rng.uniform(-0.005, 0.005, (size, size, size))).astype(np.float32)
    return data


def init_lichen_dense(size, rng):
    """Dense starting coverage — territorial competition begins immediately."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    c = size / 2.0

    # Place large patches of each species (fill ~20-30% each)
    for ch, n_patches in [(0, 5), (1, 4), (3, 3)]:  # A, B, C
        for _ in range(n_patches):
            cx = rng.uniform(0.1, 0.9) * size
            cy = rng.uniform(0.1, 0.9) * size
            cz = rng.uniform(0.1, 0.9) * size
            r = rng.uniform(0.08, 0.18) * size
            d2 = (x - cx)**2 + (y - cy)**2 + (z - cz)**2
            data[:, :, :, ch] += (0.4 * np.exp(-0.5 * d2 / r**2)).astype(np.float32)

    # Resource (channel 2) — uniform
    data[:, :, :, 2] = 0.5
    data[:, :, :, 0] = np.clip(data[:, :, :, 0], 0, 1)
    data[:, :, :, 1] = np.clip(data[:, :, :, 1], 0, 1)
    data[:, :, :, 3] = np.clip(data[:, :, :, 3], 0, 1)
    return data


def init_mycelium_foraging(size, rng):
    """Nutrient hotspots with sparse initial tips — network grows to connect food sources."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    c = size / 2.0
    z, y, x = np.mgrid[0:size, 0:size, 0:size]

    # 3-5 concentrated nutrient hotspots
    nutrient = np.full((size, size, size), 0.05, dtype=np.float64)
    n_food = rng.randint(3, 6)
    food_positions = []
    for _ in range(n_food):
        fx = rng.uniform(0.15, 0.85) * size
        fy = rng.uniform(0.15, 0.85) * size
        fz = rng.uniform(0.15, 0.85) * size
        food_positions.append((fx, fy, fz))
        r2 = (x - fx)**2 + (y - fy)**2 + (z - fz)**2
        sigma = rng.uniform(0.04, 0.08) * size
        nutrient += 0.8 * np.exp(-0.5 * r2 / sigma**2)
    data[:, :, :, 1] = np.clip(nutrient, 0, 1).astype(np.float32)

    # Seed a few tips near center (colony start)
    cx, cy, cz = c, c, c
    for _ in range(5):
        tx = int(cx + rng.uniform(-3, 3))
        ty = int(cy + rng.uniform(-3, 3))
        tz = int(cz + rng.uniform(-3, 3))
        if 0 <= tx < size and 0 <= ty < size and 0 <= tz < size:
            data[tz, ty, tx, 0] = 1.0
    return data


def init_bz_turbulence_high_amp(size, rng):
    """High-amplitude BZ initial state — survives Benjamin-Feir instability longer."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    # Amplitude 2× limit cycle — will saturate to turbulent field
    amp = 2.0
    phase = _canonical_noise(size, rng, 0.0, 2.0 * np.pi)
    data[:, :, :, 0] = amp * np.cos(phase)  # Re(A)
    data[:, :, :, 1] = amp * np.sin(phase)  # Im(A)
    data[:, :, :, 2] = phase / (2.0 * np.pi)  # Phase [0,1]
    return data


def init_fire_sparse(size, rng):
    """Fuel islands separated by firebreaks — fire jumps between patches via embers."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]

    # Scattered fuel islands (Gaussian blobs)
    fuel = np.zeros((size, size, size), dtype=np.float64)
    n_patches = rng.randint(8, 16)
    for _ in range(n_patches):
        fx = rng.uniform(0.1, 0.9) * size
        fy = rng.uniform(0.05, 0.85) * size  # bias lower (gravity)
        fz = rng.uniform(0.1, 0.9) * size
        r = rng.uniform(0.06, 0.14) * size
        d2 = (x - fx)**2 + (y - fy)**2 + (z - fz)**2
        fuel += rng.uniform(0.5, 0.9) * np.exp(-0.5 * d2 / r**2)

    data[:, :, :, 0] = np.clip(fuel, 0, 1).astype(np.float32)

    # Ignition point (bottom center)
    ic = size // 2
    for dx in range(-2, 3):
        for dz in range(-2, 3):
            ix, iz = ic + dx, ic + dz
            if 0 <= ix < size and 0 <= iz < size:
                data[iz, 1, ix, 1] = 1.0  # temperature
    # Oxygen starts at 1
    data[:, :, :, 2] = 1.0
    return data


def init_phase_separation_quench(size, rng):
    """Deep quench — starts with pre-separated patches for fast coarsening dynamics."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]

    # Coarse random field using a few overlapping Gaussian blobs
    c_field = np.zeros((size, size, size), dtype=np.float64)
    n_blobs = rng.randint(8, 15)
    for _ in range(n_blobs):
        bx = rng.uniform(0, 1) * size
        by = rng.uniform(0, 1) * size
        bz = rng.uniform(0, 1) * size
        sigma = rng.uniform(0.08, 0.18) * size
        sign = rng.choice([-1, 1])
        d2 = (x - bx)**2 + (y - by)**2 + (z - bz)**2
        c_field += sign * 0.6 * np.exp(-0.5 * d2 / sigma**2)

    # Normalize to [-0.8, 0.8] — already near binodal
    c_max = np.max(np.abs(c_field))
    if c_max > 1e-6:
        c_field = 0.8 * c_field / c_max
    data[:, :, :, 0] = c_field.astype(np.float32)
    return data


def init_element_layered(size, rng):
    """Stratified element layers — reactions happen at interfaces between materials."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    # Element IDs: C=6, O=8, Na=11, Fe=26, Cu=29
    # Bottom third: iron. Middle third: carbon. Top third: oxygen gas.
    third = size // 3
    # Fe layer (solid, dense, bottom)
    data[:, :third, :, 0] = 26.0  # Fe
    data[:, :third, :, 1] = 25.0  # temp
    data[:, :third, :, 2] = 0.0   # solid
    # C layer (solid, middle)
    data[:, third:2*third, :, 0] = 6.0  # C
    data[:, third:2*third, :, 1] = 25.0
    data[:, third:2*third, :, 2] = 0.0
    # O layer (gas, top)
    data[:, 2*third:, :, 0] = 8.0  # O
    data[:, 2*third:, :, 1] = 25.0
    data[:, 2*third:, :, 2] = 1.0  # gas phase

    # Sprinkle some Na at the interfaces for reactivity
    interface_lo = third - 1
    interface_hi = 2 * third
    n_na = max(1, size // 8)
    for _ in range(n_na):
        nx = rng.randint(0, size)
        ny = rng.choice([interface_lo, interface_hi])
        nz = rng.randint(0, size)
        if 0 <= ny < size:
            data[nz, ny, nx, 0] = 11.0  # Na
            data[nz, ny, nx, 1] = 25.0
    return data


# ── Quantum mechanics initialization functions ──

def _coulomb_potential(size, Z, r_soft=1.5):
    """Softened Coulomb potential V(r) = -Z / sqrt(r² + r_soft²), centered in grid."""
    c = size / 2.0
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    r = np.sqrt((x - c + 0.5)**2 + (y - c + 0.5)**2 + (z - c + 0.5)**2).astype(np.float64)
    V = (-Z / np.sqrt(r**2 + r_soft**2)).astype(np.float32)
    return V


def _harmonic_potential(size, omega=0.02):
    """3D harmonic trap V(r) = ½ω²r²."""
    c = size / 2.0
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    r2 = ((x - c + 0.5)**2 + (y - c + 0.5)**2 + (z - c + 0.5)**2).astype(np.float64)
    V = (0.5 * omega**2 * r2).astype(np.float32)
    return V


def _double_well_potential(size, depth=0.5, sep=0.25):
    """Two Gaussian wells separated along x-axis — for tunneling demos."""
    c = size / 2.0
    d = sep * size * 0.5
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    r_width = size * 0.08
    r1 = np.sqrt((x - c + d + 0.5)**2 + (y - c + 0.5)**2 + (z - c + 0.5)**2)
    r2 = np.sqrt((x - c - d + 0.5)**2 + (y - c + 0.5)**2 + (z - c + 0.5)**2)
    V = -depth * (np.exp(-0.5 * (r1 / r_width)**2) + np.exp(-0.5 * (r2 / r_width)**2))
    return V.astype(np.float32)


def _box_potential(size, wall_thickness=2, wall_height=8.0):
    """Square well (particle in a box) — walls at grid edges.
    V=8 gives penetration depth ~0.35 cells (99.7% confined in 2 cells)."""
    V = np.zeros((size, size, size), dtype=np.float32)
    w = wall_thickness
    V[:w, :, :] = wall_height
    V[-w:, :, :] = wall_height
    V[:, :w, :] = wall_height
    V[:, -w:, :] = wall_height
    V[:, :, :w] = wall_height
    V[:, :, -w:] = wall_height
    return V


def _gaussian_wavepacket(size, cx, cy, cz, sigma, kx=0.0, ky=0.0, kz=0.0):
    """Gaussian wavepacket Ψ = exp(-r²/4σ²) * exp(i k·r), split into Re/Im."""
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    dx = (x - cx + 0.5).astype(np.float64)
    dy = (y - cy + 0.5).astype(np.float64)
    dz = (z - cz + 0.5).astype(np.float64)
    r2 = dx**2 + dy**2 + dz**2
    envelope = np.exp(-r2 / (4.0 * sigma**2))
    phase = kx * dx + ky * dy + kz * dz
    psi_r = (envelope * np.cos(phase)).astype(np.float32)
    psi_i = (envelope * np.sin(phase)).astype(np.float32)
    # Normalize so max|Ψ| = 1 (keeps peak probability visible in renderer)
    norm = np.sqrt(np.max(psi_r**2 + psi_i**2))
    if norm > 1e-10:
        psi_r /= norm
        psi_i /= norm
    return psi_r, psi_i


def _hydrogen_orbital(size, n, l, m, Z=1.0, scale=1.0):
    """Hydrogen-like orbital ψ_nlm(r,θ,φ) = R_nl(r) * Y_lm(θ,φ).

    Returns real/imaginary parts. Uses real spherical harmonics for m≠0
    (standard chemistry convention: orbitals like dxy, dxz etc.)
    """
    from scipy.special import assoc_laguerre, sph_harm_y
    c = size / 2.0
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    dx = (x - c + 0.5).astype(np.float64)
    dy = (y - c + 0.5).astype(np.float64)
    dz = (z - c + 0.5).astype(np.float64)
    r = np.sqrt(dx**2 + dy**2 + dz**2) + 1e-10
    theta = np.arccos(np.clip(dz / r, -1, 1))
    phi = np.arctan2(dy, dx)

    # Radial part: R_nl(r) ∝ ρ^l * exp(-ρ/2) * L_{n-l-1}^{2l+1}(ρ)
    # a₀ = size/25 cells → K = a₀*Z/2 = size*Z/50 (auto-set by preset)
    # n=1 fills ~6% of grid, n=2 ~24%, n=3 ~54%
    a0 = size * scale / (25.0 * Z)
    rho = 2.0 * r / (n * a0)
    L = assoc_laguerre(rho, n - l - 1, 2 * l + 1)
    R = np.power(rho, l) * np.exp(-rho / 2.0) * L

    # Angular part: real spherical harmonic
    # sph_harm_y(l, m, theta, phi) — scipy ≥ 1.15 API
    if m == 0:
        Y = sph_harm_y(l, 0, theta, phi).real
    elif m > 0:
        # Real combination: (Y_lm + Y_l,-m) / sqrt(2) ∝ cos(mφ)
        Y = (sph_harm_y(l, m, theta, phi).real * np.sqrt(2))
    else:
        # Real combination: (Y_l,-|m| - Y_l,|m|) / (i√2) ∝ sin(|m|φ)
        Y = (sph_harm_y(l, abs(m), theta, phi).imag * np.sqrt(2))

    psi = (R * Y).astype(np.float64)
    # Normalize so max|Ψ| = 1 (keeps peak probability visible in renderer)
    norm = np.max(np.abs(psi))
    if norm > 1e-10:
        psi /= norm
    return psi.astype(np.float32), np.zeros((size, size, size), dtype=np.float32)


def init_quantum_hydrogen(size, rng):
    """Hydrogen atom 1s+2p superposition in Coulomb potential.
    Probability cloud oscillates between sphere and dumbbell shapes."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    # Superposition: 1s (sphere) + 2p_z (dumbbell)
    # Oscillation period ≈ 84 steps ≈ 1.4 sec at 60 fps
    psi_1s, _ = _hydrogen_orbital(size, n=1, l=0, m=0)
    psi_2p, _ = _hydrogen_orbital(size, n=2, l=1, m=0)
    psi_r = psi_1s + psi_2p
    psi_i = np.zeros_like(psi_r)
    # Re-normalize so max|Ψ| = 1
    norm = np.max(np.abs(psi_r))
    if norm > 1e-10:
        psi_r /= norm
    data[:, :, :, 0] = psi_r
    data[:, :, :, 1] = psi_i
    data[:, :, :, 2] = _coulomb_potential(size, Z=1.0, r_soft=1.5)
    data[:, :, :, 3] = psi_r**2 + psi_i**2
    return data


def init_quantum_orbital(size, rng):
    """Random hydrogen orbital (n=1-3) — watch standing wave patterns.
    Sometimes seeds a superposition of two orbitals for interference."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    # Pick random quantum numbers
    n = rng.randint(1, 4)  # n = 1, 2, or 3
    l = rng.randint(0, n)  # l = 0 to n-1
    m = rng.randint(-l, l + 1)  # m = -l to l

    psi_r, psi_i = _hydrogen_orbital(size, n, l, m)

    # 40% chance: superpose with a different orbital
    if rng.random() < 0.4:
        n2 = rng.randint(1, 4)
        l2 = rng.randint(0, n2)
        m2 = rng.randint(-l2, l2 + 1)
        if (n2, l2, m2) != (n, l, m):
            psi_r2, psi_i2 = _hydrogen_orbital(size, n2, l2, m2)
            weight = rng.uniform(0.3, 0.7)
            psi_r = psi_r * weight + psi_r2 * (1 - weight)
            psi_i = psi_i * weight + psi_i2 * (1 - weight)
            norm = np.sqrt(np.max(psi_r**2 + psi_i**2))
            if norm > 1e-10:
                psi_r /= norm
                psi_i /= norm

    data[:, :, :, 0] = psi_r
    data[:, :, :, 1] = psi_i
    data[:, :, :, 2] = _coulomb_potential(size, Z=1.0, r_soft=1.5)
    data[:, :, :, 3] = psi_r**2 + psi_i**2
    return data


def init_quantum_element(size, rng, atomic_number=None):
    """Render a real periodic-table element's valence orbital cloud.

    Picks an element (random if `atomic_number` is None), looks up its
    valence subshell (n, l, occupancy) from element_data.VALENCE, builds
    a |m|-degenerate superposition with random complex weights, and uses
    a Slater-screened Coulomb potential V(r) = -Z_eff/r so that orbital
    sizes stay roughly comparable across the periodic table.

    Homage to /home/user/development/periodic-table/ — every element's
    actual valence shell is renderable as a TDSE-evolving wavepacket.
    """
    from element_data import VALENCE, slater_zeff, SYMBOLS
    data = np.zeros((size, size, size, 4), dtype=np.float32)

    # Pick element. Default focus: low-Z (period 1-4) for visibility,
    # but allow the full table when explicitly requested.
    if atomic_number is None:
        # Bias toward periods 1-4 (Z 1-36) so the visualization is rich
        # — high-Z d/f orbitals get cramped at typical search sizes.
        if rng.random() < 0.85:
            Z = rng.randint(1, 37)
        else:
            Z = rng.randint(37, 119)
    else:
        Z = int(atomic_number)
    Z = max(1, min(118, Z))

    n, l, occ = VALENCE[Z]
    z_eff = slater_zeff(Z, n, l, occ)

    # Build a superposition of all (2l+1) m-states with random complex
    # weights. This produces a visually-interesting cloud rather than a
    # single oriented dumbbell/clover. Weights are normalised so peak |Ψ|=1.
    psi_r = np.zeros((size, size, size), dtype=np.float64)
    psi_i = np.zeros((size, size, size), dtype=np.float64)
    for m in range(-l, l + 1):
        # Spatial scale: hydrogen-like orbitals scale as r/Z_eff. Choose a
        # `scale` that puts the bulk of the cloud comfortably inside the
        # box — empirically scale ~ size / (n * 8) keeps things visible
        # for n=1..5 at typical sizes (64..192).
        spatial_scale = max(0.5, size / (n * 8.0 * max(1.0, z_eff ** 0.5)))
        pr, pi = _hydrogen_orbital(size, n, l, m, Z=z_eff, scale=spatial_scale)
        # Complex weight (cr + i*ci) — random unit complex
        theta = rng.uniform(0.0, 2 * np.pi)
        amp   = rng.uniform(0.5, 1.0)
        cr, ci = amp * np.cos(theta), amp * np.sin(theta)
        # (cr + i*ci) * (pr + i*pi) = (cr*pr - ci*pi) + i*(cr*pi + ci*pr)
        psi_r += cr * pr - ci * pi
        psi_i += cr * pi + ci * pr

    # Normalize peak |Ψ| = 1
    peak = float(np.sqrt(np.max(psi_r * psi_r + psi_i * psi_i)))
    if peak > 1e-10:
        psi_r /= peak
        psi_i /= peak

    data[:, :, :, 0] = psi_r.astype(np.float32)
    data[:, :, :, 1] = psi_i.astype(np.float32)
    # Slater-screened Coulomb keeps orbital scale physical across the table
    data[:, :, :, 2] = _coulomb_potential(size, Z=z_eff, r_soft=1.5)
    data[:, :, :, 3] = (psi_r * psi_r + psi_i * psi_i).astype(np.float32)
    print(f"[quantum_element] Z={Z} ({SYMBOLS[Z]}) "
          f"valence={n}{'spdf'[l]}^{occ}  Z_eff={z_eff:.2f}")
    return data


def init_quantum_multi_well(size, rng, n_wells=None):
    """Multiple Coulomb wells: paint 2-4 nuclei at random positions, each
    with its own attractive potential. The wavefunction starts as a
    superposition of 1s orbitals around each nucleus — over time, tunneling
    between wells produces molecular-orbital-like patterns (bonding /
    antibonding linear combinations form spontaneously)."""
    if n_wells is None:
        n_wells = rng.choice([2, 2, 3, 3, 4])      # weight toward 2-3
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]

    # Place nuclei at well-separated random positions (avoid box edges).
    margin = max(4, size // 6)
    centres = []
    for _ in range(int(n_wells)):
        for _try in range(20):
            cx = rng.uniform(margin, size - margin)
            cy = rng.uniform(margin, size - margin)
            cz = rng.uniform(margin, size - margin)
            ok = all(((cx-px)**2 + (cy-py)**2 + (cz-pz)**2) > (size/4)**2
                     for px, py, pz in centres)
            if ok or not centres:
                break
        centres.append((cx, cy, cz))

    psi_r = np.zeros((size, size, size), dtype=np.float64)
    psi_i = np.zeros_like(psi_r)
    V     = np.zeros_like(psi_r)
    a0 = max(2.0, size / 16.0)                    # Bohr radius in cells
    Z_each = 1.0
    r_soft = 1.5

    # Build superposed 1s orbitals + summed Coulomb potential.
    for cx, cy, cz in centres:
        d2 = (x - cx) ** 2 + (y - cy) ** 2 + (z - cz) ** 2
        d  = np.sqrt(d2)
        # 1s orbital: exp(-r/a0) (real, normalised loosely)
        amp = np.exp(-d / a0)
        # Random phase per well so initial state is a coherent superposition.
        phase = rng.uniform(0.0, 2 * np.pi)
        psi_r += amp * np.cos(phase)
        psi_i += amp * np.sin(phase)
        # Soft Coulomb: V = -Z / sqrt(r^2 + r_soft^2)
        V    -= Z_each / np.sqrt(d2 + r_soft * r_soft)

    peak = max(np.abs(psi_r).max(), np.abs(psi_i).max(), 1e-10)
    psi_r /= peak; psi_i /= peak
    data[:, :, :, 0] = psi_r.astype(np.float32)
    data[:, :, :, 1] = psi_i.astype(np.float32)
    data[:, :, :, 2] = V.astype(np.float32)
    data[:, :, :, 3] = (psi_r * psi_r + psi_i * psi_i).astype(np.float32)
    print(f"[quantum_multi_well] {len(centres)} nuclei placed")
    return data


def init_quantum_packet_scattering(size, rng):
    """Gaussian wave packet with an initial momentum heading toward a
    barrier. Demonstrates quantum tunneling (some |ψ|² appears past
    the barrier even if E_packet < V_barrier) and partial reflection.
    The barrier is a thick wall of high V perpendicular to the packet's
    direction of motion."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]

    # Packet starts at x = size/4, moving in +x.
    cx, cy, cz = size / 4.0, size / 2.0, size / 2.0
    sigma = max(2.5, size / 12.0)
    k0 = 2.0 * np.pi / max(4.0, size / 8.0)        # central wavenumber

    d2 = (x - cx) ** 2 + (y - cy) ** 2 + (z - cz) ** 2
    envelope = np.exp(-0.5 * d2 / (sigma * sigma))
    phase = k0 * (x - cx)
    psi_r = (envelope * np.cos(phase)).astype(np.float32)
    psi_i = (envelope * np.sin(phase)).astype(np.float32)

    # Barrier: thick slab at x = 5*size/8, V = +5 (taller than packet KE
    # for partial transmission via tunneling).
    V = np.zeros((size, size, size), dtype=np.float32)
    x_b_lo = int(5 * size / 8)
    x_b_hi = int(5 * size / 8) + max(2, size // 16)
    V[(x >= x_b_lo) & (x < x_b_hi)] = 5.0

    data[:, :, :, 0] = psi_r
    data[:, :, :, 1] = psi_i
    data[:, :, :, 2] = V
    data[:, :, :, 3] = psi_r * psi_r + psi_i * psi_i
    return data


def init_quantum_stark(size, rng):
    """Hydrogen 1s + uniform external electric field along Z. The Stark
    effect lifts the energy degeneracy and polarises the orbital — the
    electron cloud shifts toward the +Z (lower-potential) side over time.
    Sets V = -Z/r + F·z so the linear gradient drives the polarisation."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    psi_r, psi_i = _hydrogen_orbital(size, n=1, l=0, m=0, Z=1.0)
    data[:, :, :, 0] = psi_r
    data[:, :, :, 1] = psi_i
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    cz = (z - size / 2.0).astype(np.float64)
    F = 0.05                                       # field strength (atomic units)
    V_coul = _coulomb_potential(size, Z=1.0, r_soft=1.5)
    data[:, :, :, 2] = (V_coul + (F * cz).astype(np.float32)).astype(np.float32)
    data[:, :, :, 3] = psi_r ** 2 + psi_i ** 2
    return data


# ── Individual orbital init variants (factory) ──

def _make_orbital_init(n, l, m, label):
    """Factory for orbital init functions with specific quantum numbers."""
    def init_fn(size, rng):
        data = np.zeros((size, size, size, 4), dtype=np.float32)
        psi_r, psi_i = _hydrogen_orbital(size, n, l, m)
        data[:, :, :, 0] = psi_r
        data[:, :, :, 1] = psi_i
        data[:, :, :, 2] = _coulomb_potential(size, Z=1.0, r_soft=1.5)
        data[:, :, :, 3] = psi_r**2 + psi_i**2
        return data
    init_fn.__name__ = f'init_orbital_{label}'
    init_fn.__doc__ = f'Hydrogen {label} orbital (n={n}, l={l}, m={m}).'
    return init_fn

# Standard orbital labels: spectroscopic notation + m subscript
_ORBITAL_DEFS = [
    # (n, l, m, label)
    (1, 0, 0, '1s'),
    (2, 0, 0, '2s'),
    (2, 1, 0, '2p0'),
    (2, 1, 1, '2p1'),
    (2, 1, -1, '2p-1'),
    (3, 0, 0, '3s'),
    (3, 1, 0, '3p0'),
    (3, 1, 1, '3p1'),
    (3, 2, 0, '3d0'),
    (3, 2, 1, '3d1'),
    (3, 2, 2, '3d2'),
    (3, 2, -1, '3d-1'),
    (3, 2, -2, '3d-2'),
    (4, 0, 0, '4s'),
    (4, 1, 0, '4p0'),
    (4, 2, 0, '4d0'),
    (4, 3, 0, '4f0'),
    (4, 3, 3, '4f3'),
]

ORBITAL_INITS = {}
for _n, _l, _m, _label in _ORBITAL_DEFS:
    _fname = f'orbital_{_label}'
    ORBITAL_INITS[_fname] = _make_orbital_init(_n, _l, _m, _label)


def init_quantum_wavepacket(size, rng):
    """Gaussian wavepacket with random momentum — watch it disperse,
    bounce off walls, and interfere with itself."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    c = size / 2.0
    sigma = rng.uniform(size * 0.06, size * 0.12)

    # Random offset from center
    cx = c + rng.uniform(-size * 0.15, size * 0.15)
    cy = c + rng.uniform(-size * 0.15, size * 0.15)
    cz = c + rng.uniform(-size * 0.15, size * 0.15)

    # Random momentum (determines direction of travel)
    k_mag = rng.uniform(0.2, 1.0)
    theta = rng.uniform(0, 2 * np.pi)
    phi = rng.uniform(-np.pi / 2, np.pi / 2)
    kx = k_mag * np.cos(phi) * np.cos(theta)
    ky = k_mag * np.cos(phi) * np.sin(theta)
    kz = k_mag * np.sin(phi)

    psi_r, psi_i = _gaussian_wavepacket(size, cx, cy, cz, sigma, kx, ky, kz)
    data[:, :, :, 0] = psi_r
    data[:, :, :, 1] = psi_i
    # Box potential (particle in a box)
    data[:, :, :, 2] = _box_potential(size)
    data[:, :, :, 3] = psi_r**2 + psi_i**2
    return data


def init_quantum_harmonic(size, rng):
    """Wavepacket in harmonic trap — coherent state oscillation.
    Displaced Gaussian oscillates back and forth like a classical particle."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    c = size / 2.0
    sigma = size * 0.08

    # Displace from center (the restoring force will pull it back)
    displacement = rng.uniform(0.1, 0.25) * size
    angle = rng.uniform(0, 2 * np.pi)
    cx = c + displacement * np.cos(angle)
    cy = c + displacement * np.sin(angle)
    cz = c

    psi_r, psi_i = _gaussian_wavepacket(size, cx, cy, cz, sigma)
    data[:, :, :, 0] = psi_r
    data[:, :, :, 1] = psi_i
    data[:, :, :, 2] = _harmonic_potential(size, omega=0.02)
    data[:, :, :, 3] = psi_r**2 + psi_i**2
    return data


def init_quantum_tunneling(size, rng):
    """Wavepacket aimed at a potential barrier — watch part of it tunnel through.
    Classic quantum tunneling demonstration."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    c = size / 2.0
    sigma = size * 0.07

    # Wavepacket starts on the left, moving right
    cx = c - size * 0.2
    cy = c
    cz = c
    kx = rng.uniform(0.5, 1.2)  # rightward momentum

    psi_r, psi_i = _gaussian_wavepacket(size, cx, cy, cz, sigma, kx=kx)
    data[:, :, :, 0] = psi_r
    data[:, :, :, 1] = psi_i

    # Barrier: thin wall in the middle (Gaussian-shaped barrier along x)
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    barrier_width = rng.uniform(1.5, 4.0)
    barrier_height = rng.uniform(0.3, 1.5)
    barrier = barrier_height * np.exp(-0.5 * ((x - c) / barrier_width)**2)
    data[:, :, :, 2] = barrier.astype(np.float32)
    data[:, :, :, 3] = psi_r**2 + psi_i**2
    return data


def init_quantum_double_slit(size, rng):
    """Wavepacket approaching a double-slit barrier — produces interference pattern.
    The barrier has two gaps that act as coherent sources."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    c = size / 2.0
    sigma = size * 0.07

    # Plane wave packet moving in +x direction
    cx = c - size * 0.25
    cy = c
    cz = c
    kx = rng.uniform(0.6, 1.0)

    psi_r, psi_i = _gaussian_wavepacket(size, cx, cy, cz, sigma, kx=kx)
    data[:, :, :, 0] = psi_r
    data[:, :, :, 1] = psi_i

    # Double slit barrier at x = center
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    barrier = np.zeros((size, size, size), dtype=np.float32)
    wall_x = int(c)
    wall_thick = 2
    # Wall (V=8 — good confinement without CFL issues)
    barrier[:, :, wall_x - wall_thick:wall_x + wall_thick] = 8.0
    # Cut two slits (along y-axis, centered in z)
    slit_sep = max(3, int(size * 0.15))
    slit_width = max(2, int(size * 0.04))
    for slit_off in [-slit_sep // 2, slit_sep // 2]:
        y_start = max(0, int(c + slit_off - slit_width // 2))
        y_end = min(size, int(c + slit_off + slit_width // 2))
        barrier[:, y_start:y_end, wall_x - wall_thick:wall_x + wall_thick] = 0.0

    data[:, :, :, 2] = barrier
    data[:, :, :, 3] = psi_r**2 + psi_i**2
    return data


def init_quantum_molecule(size, rng):
    """Two-center molecular orbital — electron in potential of two nuclei.
    Seeds with a 1s-like wavefunction centered between nuclei (bonding orbital)."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    c = size / 2.0
    sigma = size * 0.1

    # Wavepacket centered between the two nuclei
    psi_r, psi_i = _gaussian_wavepacket(size, c, c, c, sigma)
    data[:, :, :, 0] = psi_r
    data[:, :, :, 1] = psi_i

    # Two-center potential is computed dynamically in the shader,
    # but we pre-compute it here for the initial |Ψ|² rendering
    sep = size * 0.25  # default separation
    r_soft = 1.5
    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    d1 = np.sqrt((x - c + sep/2 + 0.5)**2 + (y - c + 0.5)**2 + (z - c + 0.5)**2)
    d2 = np.sqrt((x - c - sep/2 + 0.5)**2 + (y - c + 0.5)**2 + (z - c + 0.5)**2)
    V = -1.0 / np.sqrt(d1**2 + r_soft**2) - 1.0 / np.sqrt(d2**2 + r_soft**2)
    data[:, :, :, 2] = V.astype(np.float32)
    data[:, :, :, 3] = psi_r**2 + psi_i**2
    return data


def init_quantum_antibonding(size, rng):
    """Antibonding molecular orbital — electron probability avoids the midpoint.
    Seeds with two out-of-phase Gaussians centered on each nucleus."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    c = size / 2.0
    sep = size * 0.25
    sigma = size * 0.07

    # Two Gaussians with opposite phase (antibonding = ψ_A - ψ_B)
    psi_r1, psi_i1 = _gaussian_wavepacket(size, c - sep/2, c, c, sigma)
    psi_r2, psi_i2 = _gaussian_wavepacket(size, c + sep/2, c, c, sigma)
    psi_r = psi_r1 - psi_r2  # destructive at midpoint
    psi_i = psi_i1 - psi_i2
    norm = np.sqrt(np.max(psi_r**2 + psi_i**2))
    if norm > 1e-10:
        psi_r /= norm
        psi_i /= norm

    data[:, :, :, 0] = psi_r
    data[:, :, :, 1] = psi_i

    z, y, x = np.mgrid[0:size, 0:size, 0:size]
    d1 = np.sqrt((x - c + sep/2 + 0.5)**2 + (y - c + 0.5)**2 + (z - c + 0.5)**2)
    d2 = np.sqrt((x - c - sep/2 + 0.5)**2 + (y - c + 0.5)**2 + (z - c + 0.5)**2)
    V = -1.0 / np.sqrt(d1**2 + 1.5**2) - 1.0 / np.sqrt(d2**2 + 1.5**2)
    data[:, :, :, 2] = V.astype(np.float32)
    data[:, :, :, 3] = psi_r**2 + psi_i**2
    return data


def init_quantum_selfinteract(size, rng):
    """Wavepacket with self-interaction (Hartree mean-field).
    For the Schrödinger-Poisson shader — starts with Gaussian, potential=0."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    c = size / 2.0
    sigma = rng.uniform(size * 0.06, size * 0.12)

    # Offset slightly from center for asymmetry
    cx = c + rng.uniform(-size * 0.1, size * 0.1)
    cy = c + rng.uniform(-size * 0.1, size * 0.1)
    cz = c + rng.uniform(-size * 0.1, size * 0.1)

    psi_r, psi_i = _gaussian_wavepacket(size, cx, cy, cz, sigma)
    data[:, :, :, 0] = psi_r
    data[:, :, :, 1] = psi_i
    # V starts at 0 — the Poisson solver builds it from |Ψ|²
    data[:, :, :, 3] = psi_r**2 + psi_i**2
    return data


def init_random_spins(size, rng):
    """Uniform 50/50 binary spins for Ising. Channel R holds {0.0, 1.0}."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    data[:, :, :, 0] = (_canonical_noise(size, rng) < 0.5).astype(np.float32)
    return data


def init_eden_seeds(size, rng):
    """Single solid voxel at the geometric centre. The Eden growth shader
    expands from any solid neighbourhood, so a 1-voxel seed is enough to
    test the rule. Toroidal boundary will eventually let two growth fronts
    collide on the back face — that's a feature for visual interest."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    c = size // 2
    data[c, c, c, 0] = 1.0
    return data


def init_eden_scattered(size, rng):
    """Several scattered solid seeds. Useful for showing competition
    between independent growth fronts."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    n_seeds = max(4, size // 24)
    # Use the supplied rng so the seed map is reproducible per trial.
    coords = rng.integers(0, size, size=(n_seeds, 3)) if hasattr(rng, 'integers') \
             else rng.randint(0, size, size=(n_seeds, 3))
    for x, y, z in coords:
        data[int(x), int(y), int(z), 0] = 1.0
    return data


def init_hodgepodge_random(size, rng):
    """Uniform random integer states in [0, 1] (normalised). The shader
    decodes int(round(v * (N-1))) so a uniform float in [0,1] yields a
    near-uniform integer distribution across the full state range
    regardless of the N parameter chosen at sim time."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    data[:, :, :, 0] = _canonical_noise(size, rng)
    return data


def init_margolus_gas(size, rng):
    """Random binary particles for the Margolus 3D lattice gas.
    Density ~25% gives a fluid regime with frequent collisions but
    plenty of vacuum for particle motion to be visible."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    data[:, :, :, 0] = (_canonical_noise(size, rng) < 0.25).astype(np.float32)
    return data


def init_margolus_blob(size, rng):
    """A dense ball of particles in vacuum — Margolus rule will
    diffusively scatter it. Useful for visualising the rule's
    transport coefficient: track how the radius grows with time."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    c = size / 2.0
    r = size / 6.0
    xx, yy, zz = np.meshgrid(np.arange(size), np.arange(size),
                             np.arange(size), indexing='ij')
    inside = ((xx - c) ** 2 + (yy - c) ** 2 + (zz - c) ** 2) < r * r
    data[:, :, :, 0] = inside.astype(np.float32)
    return data


def init_fluid_quiescent(size, rng):
    """Stable Fluids: zero velocity, zero dye. The shader's source term
    (an injected smoke plume) provides all the energy. Starting from
    rest gives a clean test of the source + advection + projection
    pipeline."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    return data


def init_fluid_turbulent(size, rng):
    """Stable Fluids: divergence-free initial velocity (multi-octave
    curl noise) + a few dye blobs. Gives the rule something to advect
    immediately rather than waiting for the source plume to develop."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    # Curl of three independent FBM scalar potentials gives a roughly
    # divergence-free field. We approximate with three independent
    # octaves of low-amplitude noise instead — cheap, looks fine.
    for ch in range(3):
        field = _canonical_noise(size, rng) - 0.5
        # Smooth via two simple averages (cheap blur).
        for _ in range(2):
            padded = np.pad(field, 1, mode='wrap')
            field = (padded[:-2, 1:-1, 1:-1] + padded[2:, 1:-1, 1:-1] +
                     padded[1:-1, :-2, 1:-1] + padded[1:-1, 2:, 1:-1] +
                     padded[1:-1, 1:-1, :-2] + padded[1:-1, 1:-1, 2:] +
                     padded[1:-1, 1:-1, 1:-1]) / 7.0
        data[:, :, :, ch] = field.astype(np.float32) * 2.0  # modest amplitude
    # Scattered dye blobs.
    n_blobs = 6
    coords = rng.integers(size // 4, 3 * size // 4, size=(n_blobs, 3)) \
             if hasattr(rng, 'integers') else \
             rng.randint(size // 4, 3 * size // 4, size=(n_blobs, 3))
    blob_r = max(2, size // 16)
    for cx, cy, cz in coords:
        x0, x1 = max(0, int(cx) - blob_r), min(size, int(cx) + blob_r)
        y0, y1 = max(0, int(cy) - blob_r), min(size, int(cy) + blob_r)
        z0, z1 = max(0, int(cz) - blob_r), min(size, int(cz) + blob_r)
        data[x0:x1, y0:y1, z0:z1, 3] = 1.0
    return data


def init_rayleigh_benard(size, rng):
    """Rayleigh-Bénard: tiny random temperature perturbation across the
    full volume to break symmetry.  Without this, the initially uniform
    field is a fixed point and convection cells never nucleate.
    Velocity = 0; temperature = small white noise scaled so it's well
    below the boundary forcing strength but enough to seed instability.
    """
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    # Small uniform-noise perturbation in the temperature (W) channel.
    if hasattr(rng, 'random'):
        noise = rng.random((size, size, size)).astype(np.float32)
    else:
        noise = rng.random_sample((size, size, size)).astype(np.float32)
    data[:, :, :, 3] = (noise - 0.5) * 0.02
    return data


# ── Inits for the 2026-05 CA additions ──────────────────────────────

def init_sandpile_uniform(size, rng):
    """Start with a uniform sub-critical grain count plus a tall central
    spike. The spike topples on step 1 and seeds the avalanche cascade
    that drives the system toward the SOC attractor."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    base = (rng.random((size, size, size)).astype(np.float32) * 4.0)
    data[:, :, :, 0] = base
    c = size // 2
    data[c, c, c, 0] = 12.0
    return data


def init_sandpile_critical(size, rng):
    """Pre-relaxed near-SOC state spanning a wide grain distribution
    so the visualiser shows immediate structure (rather than a uniform
    sub-threshold field that takes many steps to develop visible
    avalanche fronts). Values drawn uniformly from [3, 7] with a few
    super-critical pokes seed self-spanning cascades on step 1."""
    data = np.full((size, size, size, 4), 0.0, dtype=np.float32)
    data[:, :, :, 0] = (3.0 + rng.random((size, size, size)).astype(np.float32) * 4.0)
    n_pokes = max(4, size // 8)
    coords = rng.randint(size // 4, 3 * size // 4, size=(n_pokes, 3))
    for x, y, z in coords:
        data[int(x), int(y), int(z), 0] = 9.0
    return data


def init_excitable_seed(size, rng):
    """One excited cell at the centre of an otherwise rest medium —
    a single rotating-spiral or expanding-wavefront source."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    c = size // 2
    data[c, c, c, 0] = 1.0 / 7.0   # state 1 in an N=8 default
    return data


def init_excitable_random(size, rng):
    """Sparse random excited cells in a sea of rest. Asymmetric ignition
    geometry so the resulting waves break and form scroll structures
    rather than concentric shells."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    n_seeds = max(8, size // 4)
    coords = rng.randint(0, size, size=(n_seeds, 3))
    for x, y, z in coords:
        data[int(x), int(y), int(z), 0] = 1.0 / 7.0
    # Add a small refractory tail beside each seed to bias the spiral chirality.
    for x, y, z in coords:
        nx = (int(x) + 1) % size
        data[nx, int(y), int(z), 0] = 6.0 / 7.0
    return data


def init_wireworld_torus(size, rng):
    """A 3D loop of conductor with a single propagating electron head
    inserted. Produces a self-sustaining ring oscillator (the simplest
    Wireworld circuit) that runs forever in the classical rule."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    z = size // 2
    cx, cy = size // 2, size // 2
    r_outer = max(6, size // 3)
    # Build a ring of conductor in the z-mid plane.
    for ang_deg in range(0, 360, 1):
        ang = np.deg2rad(ang_deg)
        x = int(cx + r_outer * np.cos(ang))
        y = int(cy + r_outer * np.sin(ang))
        if 0 <= x < size and 0 <= y < size:
            data[x, y, z, 0] = 1.0          # conductor (state 3 = 1.0)
    # Insert one electron head + tail (states 1/3, 2/3 normalised).
    sx = int(cx + r_outer)
    if 0 <= sx < size:
        data[sx, cy, z, 0] = 1.0 / 3.0      # head
        if sx - 1 >= 0:
            data[sx - 1, cy, z, 0] = 2.0 / 3.0  # tail
    return data


def init_wireworld_lattice(size, rng):
    """Random conductor scaffold with a few sparks. Useful for the rule's
    non-classical 'living wire' regime where decay and growth are nonzero —
    you get evolving wire networks rather than a pre-built circuit."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    p_cond = 0.15
    mask = rng.random((size, size, size)) < p_cond
    field = np.zeros((size, size, size), dtype=np.float32)
    field[mask] = 1.0          # conductor everywhere it's seeded
    # Sprinkle a few electron heads to start activity.
    n_heads = max(8, size // 4)
    coords = rng.randint(0, size, size=(n_heads, 3))
    for x, y, z in coords:
        field[int(x), int(y), int(z)] = 1.0 / 3.0
    data[:, :, :, 0] = field
    return data


def init_forest_dense(size, rng):
    """Dense forest at 75% density with no fires — let the rule kindle
    its own ignitions via lightning. Best for visualising the SOC
    crossover from small fires to grid-spanning firestorms."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    tree_mask = rng.random((size, size, size)) < 0.75
    data[:, :, :, 0] = np.where(tree_mask, 0.5, 0.0).astype(np.float32)
    return data


def init_forest_burning_seed(size, rng):
    """Empty grid except for a small burning patch and ~50% trees.
    Demonstrates the cascade dynamics for a known ignition source."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    tree_mask = rng.random((size, size, size)) < 0.5
    data[:, :, :, 0] = np.where(tree_mask, 0.5, 0.0).astype(np.float32)
    c = size // 2
    rad = max(1, size // 32)
    for dx in range(-rad, rad + 1):
        for dy in range(-rad, rad + 1):
            for dz in range(-rad, rad + 1):
                if abs(dx) + abs(dy) + abs(dz) <= rad:
                    data[c + dx, c + dy, c + dz, 0] = 1.0
    return data


def init_sine_gordon_kink(size, rng):
    """Single planar kink — u jumps from 0 to 2π across the y = size/2
    plane with a tanh profile of width ~3 cells. The natural soliton
    solution of the static sine–Gordon equation in 1D, lifted to 3D
    as a planar wall. Should propagate without dispersing in the
    massless limit and oscillate around the centre under restoring force."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    y_idx = np.arange(size, dtype=np.float32)
    profile = 4.0 * np.arctan(np.exp((y_idx - size / 2.0) / 3.0))
    # Broadcast to 3D.
    u = np.broadcast_to(profile[None, :, None], (size, size, size)).copy()
    data[:, :, :, 0] = u
    return data


def init_sine_gordon_breather(size, rng):
    """Localised breather mode at the centre. Small Gaussian perturbation
    in the velocity field excites the breather, which oscillates in
    place rather than propagating. Tests the rule's energy conservation."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    coords = np.indices((size, size, size)).astype(np.float32) - size / 2.0
    r2 = np.sum(coords ** 2, axis=0)
    sigma = max(2.0, size / 16.0)
    pulse = np.exp(-r2 / (2.0 * sigma * sigma))
    data[:, :, :, 1] = (pulse * 0.5).astype(np.float32)   # velocity kick
    return data


def init_lifelike_cluster(size, rng):
    """A dense central cluster of alive cells in an empty surround,
    suitable for any Life-like rule (LtL, GoL with non-default params).
    The cluster is at ~25% density inside a sphere of radius size/8."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    coords = np.indices((size, size, size)).astype(np.float32) - size / 2.0
    r = np.sqrt(np.sum(coords ** 2, axis=0))
    inside = r < (size / 8.0)
    rand = rng.random((size, size, size))
    data[:, :, :, 0] = np.where(inside & (rand < 0.25), 1.0, 0.0).astype(np.float32)
    return data


def init_pd_random(size, rng):
    """Initial cooperator/defector distribution: ~90% cooperators with
    sparse defector seeds. At b ≈ 1.85 the defectors invade as fractal
    fronts but are pinned by cooperator clusters — produces the classic
    Nowak–May spatio-temporal chaos."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    data[:, :, :, 0] = (rng.random((size, size, size)) < 0.9).astype(np.float32)
    return data


def init_pd_invading(size, rng):
    """A single defector seed in an all-cooperator grid. With b > 1
    the defector spreads as a fractal invasion front whose shape
    depends sensitively on b."""
    data = np.ones((size, size, size, 4), dtype=np.float32)
    data[:, :, :, 1:] = 0.0
    c = size // 2
    data[c, c, c, 0] = 0.0  # one defector
    return data


def init_xy_random(size, rng):
    """Uniform random spin angles. Above the (3D) critical temperature
    T_KT ≈ 2.20 the system stays disordered; below it, order parameter
    grows and vortex lines (1D defects) become long-lived."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    data[:, :, :, 0] = rng.random((size, size, size)).astype(np.float32)
    return data


def init_xy_aligned(size, rng):
    """All spins aligned to θ=0 plus a small perturbation. Heating from
    a perfect ground state lets you watch the order parameter decay
    smoothly to its equilibrium value at the chosen temperature."""
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    data[:, :, :, 0] = 0.5 + (rng.random((size, size, size)).astype(np.float32) - 0.5) * 0.02
    return data


# ─────────────────────────────────────────────────────────────────────────
# Mesh voxelisation init
# ─────────────────────────────────────────────────────────────────────────
# Provides a reusable "initialise the grid from a 3D mesh" path so any
# rule (erosion, fossilisation, EM, fluid, growth) can run on the
# voxelised shape of an arbitrary .obj/.glb/.stl/.ply asset. Two paths:
#
#   1. Built-in procedural shapes (no external file): keys 'mesh:sphere',
#      'mesh:torus', 'mesh:cube', 'mesh:icosahedron', 'mesh:cylinder',
#      'mesh:pillar', 'mesh:bunny' (icosphere fallback).
#   2. Arbitrary file: 'mesh:/abs/path/to/foo.obj' or 'mesh:rel/path.glb'.
#
# Optional query string after the path tunes the result, e.g.
#   'mesh:sphere?radius=0.45&channel=0&value=1.0&shell=False'
#   'mesh:assets/skull.obj?channel=0&scale=0.85'
#
# Parameters:
#   channel  : which RGBA channel to populate (default 0)
#   value    : value to write into solid voxels (default 1.0)
#   scale    : fraction of grid extent the mesh fills (default 0.85)
#   shell    : if True, only the surface voxels are filled (hollow);
#              otherwise the watertight interior is also filled (solid).
#              Default False (solid).
#
# All other RGBA channels are left at zero. Shaders that need a
# different default (e.g. erosion's water/sediment fields) should
# initialise those channels themselves on the first step.
# ─────────────────────────────────────────────────────────────────────────

def _builtin_mesh(name: str):
    """Return a trimesh.Trimesh for a named built-in procedural shape,
    or None if the name isn't a built-in. The mesh is centred at the
    origin with extents in roughly [-0.5, 0.5]."""
    try:
        import trimesh
    except ImportError:
        return None
    n = name.lower()
    if n in ('sphere', 'icosahedron', 'icosphere', 'bunny'):
        return trimesh.creation.icosphere(subdivisions=4, radius=0.5)
    if n == 'torus':
        return trimesh.creation.torus(major_radius=0.35, minor_radius=0.12)
    if n in ('cube', 'box'):
        return trimesh.creation.box(extents=(0.7, 0.7, 0.7))
    if n == 'cylinder':
        return trimesh.creation.cylinder(radius=0.3, height=0.8, sections=32)
    if n == 'pillar':
        return trimesh.creation.box(extents=(0.3, 0.9, 0.3))
    if n == 'cone':
        return trimesh.creation.cone(radius=0.4, height=0.8, sections=32)
    if n == 'capsule':
        return trimesh.creation.capsule(radius=0.2, height=0.7, count=(16, 16))
    return None


def voxelize_mesh(mesh_or_path, size: int, scale: float = 0.85,
                  shell: bool = False) -> np.ndarray:
    """Voxelise a mesh into a (size, size, size) bool array.

    Args:
      mesh_or_path: a trimesh.Trimesh, a path string to a mesh file, or
                    the name of a built-in shape (e.g. 'sphere').
      size: cubic grid resolution.
      scale: fraction of the grid the mesh occupies along its longest
             axis (0.85 leaves a 7.5% margin each side).
      shell: when True returns only surface voxels (hollow); when False
             also fills the watertight interior (default).

    Returns:
      np.ndarray of shape (size, size, size), dtype=bool.
    """
    try:
        import trimesh
    except ImportError as e:
        raise RuntimeError(
            "voxelize_mesh requires the 'trimesh' package "
            "(pip install trimesh). " + str(e))

    if isinstance(mesh_or_path, trimesh.Trimesh):
        mesh = mesh_or_path.copy()
    elif isinstance(mesh_or_path, str):
        builtin = _builtin_mesh(mesh_or_path)
        if builtin is not None:
            mesh = builtin
        else:
            mesh = trimesh.load(mesh_or_path, force='mesh')
            if not isinstance(mesh, trimesh.Trimesh):
                raise RuntimeError(
                    f"voxelize_mesh: '{mesh_or_path}' did not load as a single mesh")
    else:
        raise TypeError(f"voxelize_mesh: unsupported mesh source {type(mesh_or_path)}")

    # Centre and scale the mesh so its longest axis fits `scale * size`
    # voxels, then translate to occupy [0, size).
    extents = mesh.extents
    longest = float(max(extents)) if max(extents) > 0 else 1.0
    target_extent = scale * size
    s = target_extent / longest
    mesh.apply_translation(-mesh.bounds.mean(axis=0))
    mesh.apply_scale(s)
    mesh.apply_translation(np.full(3, size * 0.5))

    pitch = 1.0  # one voxel per grid cell after the scale above
    grid = np.zeros((size, size, size), dtype=bool)
    try:
        # Surface voxelisation (always works, watertightness not required).
        vox = mesh.voxelized(pitch=pitch)
        if not shell:
            try:
                vox = vox.fill()  # requires watertight mesh
            except Exception:
                # Non-watertight: fall back to per-cell point-in-mesh.
                xs, ys, zs = np.meshgrid(
                    np.arange(size) + 0.5,
                    np.arange(size) + 0.5,
                    np.arange(size) + 0.5,
                    indexing='ij')
                pts = np.stack([xs, ys, zs], axis=-1).reshape(-1, 3)
                inside = mesh.contains(pts).reshape(size, size, size)
                grid |= inside
                return grid
        # Splat the (possibly filled) voxel grid into the cubic array.
        pts = vox.points  # world-space cell centres
        idx = np.round(pts).astype(np.int64)
        ok = (
            (idx[:, 0] >= 0) & (idx[:, 0] < size) &
            (idx[:, 1] >= 0) & (idx[:, 1] < size) &
            (idx[:, 2] >= 0) & (idx[:, 2] < size)
        )
        idx = idx[ok]
        grid[idx[:, 0], idx[:, 1], idx[:, 2]] = True
    except Exception as e:
        # Last-ditch fallback: surface-sample then point-in-mesh test.
        print(f"[voxelize_mesh] direct path failed ({e}); using contains() fallback")
        xs, ys, zs = np.meshgrid(
            np.arange(size) + 0.5,
            np.arange(size) + 0.5,
            np.arange(size) + 0.5,
            indexing='ij')
        pts = np.stack([xs, ys, zs], axis=-1).reshape(-1, 3)
        grid = mesh.contains(pts).reshape(size, size, size)
    return grid


def _parse_mesh_init_spec(spec: str):
    """Parse 'mesh:<source>?key=val&...' into (source, kwargs).

    Returns (source_str, dict). Unknown keys are ignored. Numeric and
    bool values are auto-coerced.
    """
    assert spec.startswith('mesh:'), spec
    body = spec[len('mesh:'):]
    if '?' in body:
        source, qs = body.split('?', 1)
    else:
        source, qs = body, ''
    params: dict = {}
    if qs:
        for pair in qs.split('&'):
            if not pair or '=' not in pair:
                continue
            k, v = pair.split('=', 1)
            v_lower = v.lower()
            if v_lower in ('true', 'false'):
                params[k] = (v_lower == 'true')
                continue
            try:
                if '.' in v or 'e' in v_lower:
                    params[k] = float(v)
                else:
                    params[k] = int(v)
            except ValueError:
                params[k] = v
    return source, params


def init_mesh_from_spec(spec: str, size: int, rng) -> np.ndarray:
    """Build a (size, size, size, 4) f32 init array from a 'mesh:...' spec."""
    source, p = _parse_mesh_init_spec(spec)
    channel = int(p.get('channel', 0))
    value = float(p.get('value', 1.0))
    scale = float(p.get('scale', 0.85))
    shell = bool(p.get('shell', False))
    grid = voxelize_mesh(source, size, scale=scale, shell=shell)
    data = np.zeros((size, size, size, 4), dtype=np.float32)
    if 0 <= channel < 4:
        data[..., channel] = grid.astype(np.float32) * value
    return data


# ── L-system / graph-rewriting init ──────────────────────────────────
# Stochastic context-free L-systems with a 3D turtle interpreter that
# rasterises branch segments into the voxel grid. Used as a generative
# init source for tree/coral/dendritic/lightning structures that CA rules
# can then animate (grow, dissolve, react with, etc.).
#
# Spec syntax (mirrors mesh:): 'lsystem:<preset>?key=val&...'
#   channel=N      (0..3, default 0) — RGBA channel to write
#   value=F        (default 1.0)     — written magnitude
#   depth=N        (default per preset) — production iterations
#   angle=F        (degrees, default per preset) — turtle turn step
#   step=F         (default per preset) — turtle move length (voxels)
#   width=F        (default 1.0)     — initial branch radius (voxels)
#   width_decay=F  (default 0.7)     — multiplicative on branch ('!')
#   seed=N         (default 0)       — stochastic-rule RNG seed
#   axis=str       (default 'y')     — initial growth direction ('x','y','z')
#
# Production rules support stochastic alternatives: list of (weight, rhs).
# Turtle alphabet (Lindenmayer/Prusinkiewicz convention):
#   F        — move forward `step` voxels, painting a fat segment
#   f        — move forward `step` voxels without painting
#   + -      — yaw  by ±angle (around current up axis)
#   & ^      — pitch by ±angle (around current right axis)
#   / \      — roll  by ±angle (around current heading axis)
#   |        — turn 180° (yaw)
#   [        — push turtle state
#   ]        — pop  turtle state
#   !        — multiply branch width by `width_decay`
#   X..Z A..E — non-terminal placeholders (no turtle effect)


LSYSTEM_PRESETS = {
    # 3D fractal tree (Prusinkiewicz-style with random branch angles)
    'tree': {
        'axiom': 'A',
        'rules': {
            'A': [(1.0, '!F[&FA][^FA][/&FA][\\^FA]')],
        },
        'depth': 4,
        'angle': 25.0,
        'step':  3.0,
        'width': 2.0,
        'width_decay': 0.65,
    },
    # Bushy fern with fine sub-branching
    'fern': {
        'axiom': 'X',
        'rules': {
            'X': [(0.5, 'F[+X]F[-X]+X'),
                  (0.5, 'F[&X][^X]F[/X][\\X]+X')],
        },
        'depth': 4,
        'angle': 22.5,
        'step':  2.5,
        'width': 1.2,
        'width_decay': 0.85,
    },
    # Coral-like irregular branching
    'coral': {
        'axiom': 'A',
        'rules': {
            'A': [(0.5, '!F[+A][-A][&A][^A]'),
                  (0.3, '!F[/A][\\A]F[+A]'),
                  (0.2, '!FF[&A][+A]')],
            'F': [(1.0, 'F')],
        },
        'depth': 5,
        'angle': 35.0,
        'step':  4.0,
        'width': 2.5,
        'width_decay': 0.7,
    },
    # Lightning bolt (sparse, downward-biased)
    'lightning': {
        'axiom': 'A',
        'rules': {
            'A': [(0.6, 'F[+A][-A]A'),
                  (0.4, 'F[&A]A')],
        },
        'depth': 5,
        'angle': 18.0,
        'step':  3.0,
        'width': 1.5,
        'width_decay': 0.8,
    },
    # Snowflake-like dendrite (6-fold symmetric branching)
    'dendrite': {
        'axiom': 'A',
        'rules': {
            'A': [(1.0, '!F[+B][-B][&B][^B][/B][\\B]')],
            'B': [(1.0, '!F[+F][-F]')],
        },
        'depth': 3,
        'angle': 60.0,
        'step':  4.0,
        'width': 1.8,
        'width_decay': 0.7,
    },
}


def _lsystem_expand(axiom: str, rules: dict, depth: int, rng) -> str:
    s = axiom
    for _ in range(depth):
        out = []
        for ch in s:
            if ch in rules:
                alts = rules[ch]
                weights = [w for w, _ in alts]
                total = sum(weights)
                r = rng.random() * total
                acc = 0.0
                chosen = alts[-1][1]
                for w, rhs in alts:
                    acc += w
                    if r <= acc:
                        chosen = rhs
                        break
                out.append(chosen)
            else:
                out.append(ch)
        s = ''.join(out)
        # Safety cap: don't let strings grow past a few MB of chars.
        if len(s) > 2_000_000:
            break
    return s


def _lsystem_segments(prog: str, size: int, *, angle_deg: float,
                      step: float, width: float, width_decay: float,
                      axis: str = 'y'):
    """Run the turtle interpreter and return a list of
    (p0, p1, w) tuples in voxel coordinates."""
    a = math.radians(angle_deg)
    ca, sa = math.cos(a), math.sin(a)

    def rot(v, axis_v, c, s):
        # Rodrigues rotation.
        v = np.asarray(v, dtype=np.float64)
        k = np.asarray(axis_v, dtype=np.float64)
        k /= (np.linalg.norm(k) + 1e-12)
        return v * c + np.cross(k, v) * s + k * np.dot(k, v) * (1.0 - c)

    # Initial frame: heading along +axis, up perpendicular.
    if axis == 'x':
        H = np.array([1.0, 0.0, 0.0]); U = np.array([0.0, 1.0, 0.0])
    elif axis == 'z':
        H = np.array([0.0, 0.0, 1.0]); U = np.array([1.0, 0.0, 0.0])
    else:  # 'y'
        H = np.array([0.0, 1.0, 0.0]); U = np.array([1.0, 0.0, 0.0])
    L = np.cross(H, U)  # left

    # Start near bottom-centre so growth rises into the volume.
    pos = np.array([size * 0.5, size * 0.1, size * 0.5])
    if axis == 'x':
        pos = np.array([size * 0.1, size * 0.5, size * 0.5])
    elif axis == 'z':
        pos = np.array([size * 0.5, size * 0.5, size * 0.1])

    w = float(width)
    stack = []
    segments = []
    for ch in prog:
        if ch == 'F':
            new_pos = pos + H * step
            segments.append((pos.copy(), new_pos.copy(), w))
            pos = new_pos
        elif ch == 'f':
            pos = pos + H * step
        elif ch == '+':  # yaw +
            H = rot(H, U, ca, sa); L = np.cross(H, U)
        elif ch == '-':  # yaw -
            H = rot(H, U, ca, -sa); L = np.cross(H, U)
        elif ch == '&':  # pitch +
            H = rot(H, L, ca, sa); U = np.cross(L, H)
        elif ch == '^':  # pitch -
            H = rot(H, L, ca, -sa); U = np.cross(L, H)
        elif ch == '/':  # roll +
            U = rot(U, H, ca, sa); L = np.cross(H, U)
        elif ch == '\\':  # roll -
            U = rot(U, H, ca, -sa); L = np.cross(H, U)
        elif ch == '|':  # 180° yaw
            H = -H; L = -L
        elif ch == '[':
            stack.append((pos.copy(), H.copy(), U.copy(), L.copy(), w))
        elif ch == ']':
            if stack:
                pos, H, U, L, w = stack.pop()
                pos = pos.copy(); H = H.copy(); U = U.copy(); L = L.copy()
        elif ch == '!':
            w = max(0.5, w * width_decay)
        # other letters (A..E, X..Z) are non-terminals and have no
        # geometric effect.
    return segments


def _rasterise_segment(grid: np.ndarray, p0, p1, radius: float, value: float):
    """Stamp a fat line segment into a (S,S,S) f32 grid using max blending.

    Walks along the segment in unit voxel steps, stamping a sphere of the
    given radius at each step. Cheap; total work is O(segments × length × r³).
    """
    S = grid.shape[0]
    p0 = np.asarray(p0, dtype=np.float64)
    p1 = np.asarray(p1, dtype=np.float64)
    d = p1 - p0
    L = float(np.linalg.norm(d))
    if L < 1e-6:
        steps = 1
    else:
        steps = max(1, int(L) + 1)
    rad = max(1, int(math.ceil(radius)))
    r2 = radius * radius
    for s in range(steps + 1):
        t = s / steps if steps > 0 else 0.0
        c = p0 + d * t
        cx, cy, cz = int(round(c[0])), int(round(c[1])), int(round(c[2]))
        x0, x1 = max(0, cx - rad), min(S - 1, cx + rad)
        y0, y1 = max(0, cy - rad), min(S - 1, cy + rad)
        z0, z1 = max(0, cz - rad), min(S - 1, cz + rad)
        if x0 > x1 or y0 > y1 or z0 > z1:
            continue
        # Vectorised distance test inside the bbox.
        xs = np.arange(x0, x1 + 1) - c[0]
        ys = np.arange(y0, y1 + 1) - c[1]
        zs = np.arange(z0, z1 + 1) - c[2]
        d2 = (xs[:, None, None] ** 2 +
              ys[None, :, None] ** 2 +
              zs[None, None, :] ** 2)
        mask = d2 <= r2
        sub = grid[x0:x1 + 1, y0:y1 + 1, z0:z1 + 1]
        np.maximum(sub, value * mask.astype(np.float32), out=sub)


def _parse_lsystem_spec(spec: str):
    """Parse 'lsystem:<preset>?key=val&...' → (preset_name, kwargs)."""
    assert spec.startswith('lsystem:'), spec
    body = spec[len('lsystem:'):]
    if '?' in body:
        name, qs = body.split('?', 1)
    else:
        name, qs = body, ''
    params: dict = {}
    if qs:
        for pair in qs.split('&'):
            if not pair or '=' not in pair:
                continue
            k, v = pair.split('=', 1)
            v_lower = v.lower()
            if v_lower in ('true', 'false'):
                params[k] = (v_lower == 'true')
                continue
            try:
                if '.' in v or 'e' in v_lower:
                    params[k] = float(v)
                else:
                    params[k] = int(v)
            except ValueError:
                params[k] = v
    return name, params


def init_lsystem_from_spec(spec: str, size: int, rng) -> np.ndarray:
    """Build a (size, size, size, 4) f32 init array from an 'lsystem:...' spec."""
    name, p = _parse_lsystem_spec(spec)
    if name not in LSYSTEM_PRESETS:
        raise KeyError(f"Unknown L-system preset {name!r}; "
                       f"available: {sorted(LSYSTEM_PRESETS)}")
    cfg = LSYSTEM_PRESETS[name]
    channel = int(p.get('channel', 0))
    value = float(p.get('value', 1.0))
    depth = int(p.get('depth', cfg.get('depth', 4)))
    angle = float(p.get('angle', cfg.get('angle', 25.0)))
    step = float(p.get('step', cfg.get('step', 4.0)))
    width = float(p.get('width', cfg.get('width', 1.5)))
    width_decay = float(p.get('width_decay', cfg.get('width_decay', 0.7)))
    axis = str(p.get('axis', 'y'))
    seed = int(p.get('seed', 0))

    # Scale step/width to grid size if a base size of 64 was assumed.
    scale = size / 64.0
    step *= scale
    width *= scale

    py_rng = random.Random(seed)
    prog = _lsystem_expand(cfg['axiom'], cfg['rules'], depth, py_rng)
    segments = _lsystem_segments(
        prog, size, angle_deg=angle, step=step,
        width=width, width_decay=width_decay, axis=axis)

    grid = np.zeros((size, size, size), dtype=np.float32)
    for p0, p1, w in segments:
        _rasterise_segment(grid, p0, p1, max(0.5, w), value)

    data = np.zeros((size, size, size, 4), dtype=np.float32)
    if 0 <= channel < 4:
        data[..., channel] = grid
    return data


